            const svg = document.getElementById('phallus-svg');

            // Cố định gốc ở dưới cùng để khi dài ra sẽ vươn lên trên
            svg.style.transformOrigin = "bottom center";

            // Lấy 15cm làm mốc chuẩn (scale = 1)
            // Chiều dài (trục Y) thay đổi tỷ lệ thuận với kích thước
            const scaleY = value / 17;

            // Độ dày (trục X) chỉ thay đổi một chút để trông tự nhiên, không bị quá dị dạng
            const scaleX = 1 + (value - 17) * 0.025;

            // Áp dụng hiệu ứng
            svg.style.transform = `scale(${scaleX}, ${scaleY})`;
            selectedData.phallusSize = value;
