    box-sizing: border-box; z-index: 1; 
}

.axis-label { position: absolute; font-family: monospace; font-size: 8px; color: #8B6914; font-weight: bold; padding: 1px; pointer-events: none; z-index: 2; opacity: 0.6; }

.map-item { position: absolute; display: flex; align-items: center; justify-content: center; box-sizing: border-box; transition: transform 0.2s, filter 0.2s; z-index: 10; cursor: pointer; }
.map-building { width: 100%; height: 100%; display: flex; align-items: center; justify-content: center; background: linear-gradient(135deg, #FFF9EB 0%, #E8D4A8 100%); border: 1px solid #8B6914; border-radius: 20%; box-shadow: 2px 2px 4px rgba(0,0,0,0.4); font-size: 1rem; }
.map-building:hover { transform: scale(1.3); z-index: 50; filter: drop-shadow(0 0 8px #C9A227); }
.map-monster { border-color: #8B2323; background: rgba(139,58,58,0.7); font-size: 0.9rem; }
.map-resource { border-color: #2D5016; background: rgba(58,107,53,0.7); font-size: 0.9rem; }

.road-layer { position: absolute; top: 0; left: 0; width: 100%; height: 100%; z-index: 3; pointer-events: none; filter: drop-shadow(0px 2px 2px rgba(0,0,0,0.5)); }
.wall-layer { position: absolute; top: 0; left: 0; width: 100%; height: 100%; z-index: 4; pointer-events: none; filter: drop-shadow(2px 3px 4px rgba(0,0,0,0.6)); }
.node-layer { position: absolute; top: 0; left: 0; width: 100%; height: 100%; z-index: 5; pointer-events: none; }
.interactive-cell { position: absolute; pointer-events: auto; cursor: pointer; transition: filter 0.2s; }
.interactive-cell:hover .map-road { background: #a58058; }
.interactive-cell:hover .map-wall { filter: brightness(1.3); }

.map-road { position: absolute; background: #8c6a46; }
.map-wall { position: absolute; background-color: #5a5a5a; background-image: linear-gradient(45deg, rgba(0,0,0,0.15) 25%, transparent 25%, transparent 75%, rgba(0,0,0,0.15) 75%, rgba(0,0,0,0.15)), linear-gradient(45deg, rgba(0,0,0,0.15) 25%, transparent 25%, transparent 75%, rgba(0,0,0,0.15) 75%, rgba(0,0,0,0.15)); background-size: 10px 10px; background-position: 0 0, 5px 5px; }
.map-wall-node { position: absolute; background: #4a4a4a; border: 2px solid #222; border-radius: 4px; box-shadow: inset 0 0 4px rgba(255,255,255,0.2), 2px 2px 5px rgba(0,0,0,0.5); }
.map-gate { position: absolute; z-index: 6; cursor: pointer; background: linear-gradient(180deg, #5C3D1E 0%, #3D2914 100%); border: 2px solid #1A0F0A; border-radius: 4px; box-shadow: 0 4px 8px rgba(0,0,0,0.5); color: #D4C4A0; display: flex; align-items: center; justify-content: center; font-size: 16px; }
.map-gate:hover { transform: scale(1.1); border-color: #C9A227; z-index: 20; }

.build-mode-active { background: linear-gradient(180deg, #2D5016 0%, #1a300c 100%) !important; border-color: #7CFC00 !important; box-shadow: 0 0 10px #7CFC00; color: #fff !important; }
#build-cursor { position: absolute; width: 30px; height: 30px; background: rgba(124, 252, 0, 0.4); border: 2px dashed #7CFC00; z-index: 999; pointer-events: none; display: none; align-items: center; justify-content: center; font-size: 8px; font-weight: bold; color: white; text-shadow: 1px 1px 2px black; box-sizing: border-box; box-shadow: 0 0 10px rgba(124, 252, 0, 0.5); }
.path-preview-cell { position: absolute; background: rgba(255, 153, 0, 0.4); border: 1px dashed #FF9900; pointer-events: none; z-index: 998; }
.build-action-menu { position: absolute; z-index: 1000; background: rgba(30, 20, 10, 0.95); border: 2px solid #C9A227; border-radius: 25px; padding: 5px; display: none; transform: translate(-50%, -120%); box-shadow: 0 4px 15px rgba(0,0,0,0.6); white-space: nowrap; }
.build-action-btn { background: transparent; border: none; color: #D4C4A0; font-family: 'Noto Serif', serif; font-weight: bold; cursor: pointer; padding: 6px 15px; font-size: 0.9em; transition: 0.2s; border-radius: 20px; outline: none; }
.build-action-btn:hover { background: #8B6914; color: #FFF; }
.build-action-divider { display: inline-block; width: 1px; height: 15px; background: #8B6914; vertical-align: middle; margin: 0 5px; }

.map-info-panel { position: absolute; bottom: 20px; right: 20px; width: 320px; background: linear-gradient(145deg, #FFF9EB, #F2E3C4); border: 2px solid #8B6914; border-radius: 8px; padding: 15px; box-shadow: 0 8px 20px rgba(0,0,0,0.6); display: none; z-index: 1000; }
.info-header { display: flex; align-items: center; justify-content: space-between; border-bottom: 2px solid #8B6914; padding-bottom: 8px; margin-bottom: 10px; }
.info-actions { display: flex; gap: 8px; margin-top: 12px; padding-top: 12px; border-top: 1px dashed #D4C4A0; }

.action-btn { flex: 1; padding: 8px 5px; border-radius: 4px; font-family: 'Noto Serif', serif; font-size: 0.85em; font-weight: 800; cursor: pointer; transition: all 0.2s; text-align: center; }
.btn-upgrade { background: linear-gradient(180deg, #4a3020 0%, #2a1a0a 100%); color: #F5E6C8; border: 1px solid #C9A227; }
.btn-upgrade:hover { background: #C9A227; color: #1A0F0A; }
.btn-destroy { background: linear-gradient(180deg, #8B2323 0%, #5a1010 100%); color: #F5E6C8; border: 1px solid #ff4d4d; }
.btn-destroy:hover { background: #ff4d4d; color: #fff; }
.btn-build { background: linear-gradient(180deg, #2D5016 0%, #1a300c 100%); color: #F5E6C8; border: 1px solid #7CFC00; width: 100%; margin-top: 10px; }
.btn-build:hover { background: #7CFC00; color: #1A0F0A; }

.build-input { width: 100%; box-sizing: border-box; padding: 8px; margin-bottom: 8px; background: rgba(255,255,255,0.6); border: 1px solid #8B6914; border-radius: 4px; font-family: 'Noto Serif', serif; font-weight: bold; }

#pane-map:fullscreen { background: #0a0806; padding: 10px; }
#pane-map:-webkit-full-screen { background: #0a0806; padding: 10px; }
#pane-map:fullscreen .map-viewport { height: calc(100vh - 80px); border-radius: 8px; border: 2px solid #8B6914; }
#pane-map:-webkit-full-screen .map-viewport { height: calc(100vh - 80px); border-radius: 8px; border: 2px solid #8B6914; }

/* ==========================================================================
   5. MODULE: PHÁP LỆNH (Decree & Politics)
   ========================================================================== */
.decree-card { background: rgba(255, 255, 255, 0.4); border: 1px solid #C9A227; border-radius: 6px; padding: 15px; position: relative; transition: transform 0.2s, box-shadow 0.2s; }
.decree-card:hover { background: rgba(255, 255, 255, 0.7); box-shadow: 0 4px 10px rgba(139, 105, 20, 0.2); }
.decree-title { font-size: 1.1em; font-weight: 900; color: #8B2323; margin-bottom: 8px; display: flex; justify-content: space-between; align-items: center; border-bottom: 2px solid rgba(139,105,20,0.3); padding-bottom: 5px; }
.decree-meta { font-size: 0.85em; color: #6B5344; margin-bottom: 10px; font-weight: bold; }
.decree-content { font-size: 0.95em; color: #2C1810; margin-bottom: 12px; line-height: 1.5; }
.decree-effect { font-size: 0.9em; background: rgba(45, 80, 22, 0.1); border-left: 4px solid #2D5016; padding: 8px 12px; color: #2D5016; font-style: italic; }
.decree-empty { text-align: center; padding: 30px; color: #8B6914; font-style: italic; border: 1px dashed #C9A227; background: rgba(0,0,0,0.02); }

.new-decree-section { margin-top: 20px; padding: 20px; background: linear-gradient(135deg, rgba(201, 162, 39, 0.1) 0%, rgba(201, 162, 39, 0.2) 100%); border: 2px dashed #c9a227; border-radius: 10px; }
.new-decree-title { display: flex; align-items: center; gap: 10px; font-size: 1.1em; font-weight: 900; color: #2C1810; margin-bottom: 15px; }
.new-decree-form-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 15px; margin-bottom: 15px; }
.new-decree-form-group { display: flex; flex-direction: column; }
.new-decree-form-group.full-width { grid-column: 1 / -1; }
.new-decree-form-group label { font-size: 0.9em; color: #4A3728; margin-bottom: 5px; font-weight: bold; }
.new-decree-input, .new-decree-select { padding: 10px; border: 2px solid #8b7355; border-radius: 5px; font-family: 'Noto Serif', serif; font-size: 0.95em; background: rgba(255,255,255,0.7); color: #2C1810; }
.new-decree-textarea { width: 100%; min-height: 100px; padding: 12px; border: 2px solid #8b7355; border-radius: 5px; font-family: 'Noto Serif', serif; font-size: 0.95em; background: rgba(255,255,255,0.7); color: #2C1810; resize: vertical; box-sizing: border-box; }

.add-decree-btn { background: linear-gradient(135deg, #c9a227 0%, #a08020 100%); color: #fff; border: none; padding: 12px 30px; border-radius: 25px; cursor: pointer; font-family: 'Noto Serif', serif; font-size: 1em; font-weight: bold; transition: all 0.3s; margin: 0 auto; display: flex; align-items: center; gap: 8px; box-shadow: 0 4px 10px rgba(201, 162, 39, 0.4); }

.pending-changes-section { margin-top: 20px; padding: 20px; background: linear-gradient(135deg, rgba(139, 35, 35, 0.05) 0%, rgba(139, 35, 35, 0.1) 100%); border: 2px solid #8b2323; border-radius: 10px; display: none; }
.pending-title { font-size: 1.1em; font-weight: bold; color: #8b2323; margin-bottom: 10px; }
.pending-item { display: flex; align-items: center; justify-content: space-between; padding: 8px 12px; background: rgba(255, 255, 255, 0.6); border-radius: 5px; margin-bottom: 8px; font-size: 0.9em; border-left: 4px solid #8b2323; }
.pending-tag-new { background: #c9a227; color: #fff; padding: 2px 8px; border-radius: 10px; font-size: 0.8em; font-weight: bold; }
.pending-tag-mod { background: #2D5016; color: #fff; padding: 2px 8px; border-radius: 10px; font-size: 0.8em; font-weight: bold; }
.pending-tag-del { background: #8b2323; color: #fff; padding: 2px 8px; border-radius: 10px; font-size: 0.8em; font-weight: bold; }
.decree-edit-form { display: none; padding: 15px; background: rgba(255, 255, 255, 0.5); border-top: 1px dashed #8b7355; margin-top: 10px; }

/* ==========================================================================
   6. RESPONSIVE QUERIES
   ========================================================================== */
@media (max-width: 600px) { 
    .mini-card-grid { grid-template-columns: 1fr; } 
    .dashboard-container { margin: 5px; border-width: 2px; } 
    .header-territory-name { font-size: 1.3em; } 
}

