                  style="cursor: pointer; padding: 4px 8px; background: rgba(255,255,255,0.1); border-radius: 4px; border: 1px dashed #C9A227; display: inline-block; transition: 0.2s;"
                  onclick="openLordProfileModal()"
                  onmouseover="this.style.background='rgba(255,255,255,0.2)'" 
