    </div>

    <div class="content-area">

        <div id="pane-status" class="tab-pane" style="display: block;">
            <details class="section-box" open>
                <summary class="section-title"><span>📍 LÃNH ĐỊA</span> <span class="indicator">▼</span></summary>
