<script type="module">
    /* ==========================================================================
       PHẦN 1: LOGIC MỞ/ĐÓNG MODAL VÀ TAB (HỒ SƠ LÃNH CHÚA & NỮ TƯỚNG)
       ========================================================================== */
    window.openLordProfileModal = function() {
        document.getElementById('lord-profile-modal').style.display = 'flex';
    };

    window.closeLordProfileModal = function() {
        document.getElementById('lord-profile-modal').style.display = 'none';
    };

    window.switchProfileTab = function(tabId, btnElement) {
        const modal = document.getElementById('lord-profile-modal');
        modal.querySelectorAll('.tab-pane').forEach(pane => pane.style.display = 'none');
        modal.querySelectorAll('.tab-btn').forEach(btn => btn.classList.remove('active'));
        document.getElementById(tabId).style.display = 'block';
        btnElement.classList.add('active');
    };

    // Chuyển Tab cho bảng Nữ Tướng
    window.switchFemaleTab = function(tabId, btnElement) {
        const modal = document.getElementById('female-hero-modal');
        modal.querySelectorAll('.tab-pane').forEach(pane => pane.style.display = 'none');
        modal.querySelectorAll('.tab-btn').forEach(btn => {
            btn.classList.remove('active');
            btn.style.borderBottom = "none";
            btn.style.background = "transparent";
            btn.style.color = "#ff99cc";
        });
        document.getElementById(tabId).style.display = 'block';
        btnElement.classList.add('active');
        btnElement.style.borderBottom = "4px solid #cc0066";
        btnElement.style.background = "#4d0026";
        btnElement.style.color = "#FFF";
    };

    // Cập nhật hàm mở Modal: Lấy trực tiếp từ MVU
    window.openFemaleHeroModal = function(name, job, hc, dl) {
        // 1. Cập nhật các thông số cơ bản
        $('#fh-name').text(name);
        $('#fh-class').text(job || 'Chưa rõ');

        // 2. Gán trực tiếp Hảo cảm và Đọa lạc vào UI từ dữ liệu truyền vào (Đã là số chuẩn từ MVU)
        $('#fh-haocam').text(hc !== undefined ? hc : 0);
        $('#fh-doalac').text(dl !== undefined ? dl : 0);

        // Mở bảng lên
        document.getElementById('female-hero-modal').style.display = 'flex';
        const firstTab = document.querySelector('#female-hero-modal .profile-tabs .tab-btn');
        if(firstTab) window.switchFemaleTab('fh-tab-info', firstTab);
    };

    window.closeFemaleHeroModal = function() {
        document.getElementById('female-hero-modal').style.display = 'none';
    };

    window.switchTab = function(paneId, btn) {
        $('.tab-pane').hide();
        $('#' + paneId).show();
        $('.tab-btn').removeClass('active');
        $(btn).addClass('active');
        // Reset map size nếu mở tab bản đồ
        if (paneId === 'pane-map' && typeof window.mapReset === 'function') setTimeout(window.mapReset, 50); 
    };

    // Hiệu ứng gợn sóng khi bấm nút
    window.addRippleEffect = function(e) {
        const btn = e.currentTarget;
        const ripple = document.createElement('span');
        ripple.className = 'ripple';
        const rect = btn.getBoundingClientRect();
        const size = Math.max(rect.width, rect.height);
        ripple.style.width = ripple.style.height = size + 'px';
        ripple.style.left = (e.clientX - rect.left - (size / 2)) + 'px';
        ripple.style.top = (e.clientY - rect.top - (size / 2)) + 'px';
