    // --- Tối ưu: Hàm lấy dữ liệu MVU ngắn gọn ---
    window.getMVUVars = function() {
        return typeof getAllVariables === 'function' ? getAllVariables() : {};
    };

    // --- Hàm lấy dữ liệu an toàn từ Object theo đường dẫn string ---
    window.safeGet = function(obj, pathString, defaultValue) {
        if (!obj) return defaultValue;
        const keys = pathString.split('.');
        let current = obj;
        for (let i = 0; i < keys.length; i++) {
            let key = keys[i];
            if (current === undefined || current === null) return defaultValue;
            // Xử lý tự động chuyển đổi dấu gạch ngang sang gạch dưới theo chuẩn MVU
            const actualKey = key.replace(/-/g, '\x5F');
            current = current[actualKey];
        }
        return current !== undefined ? current : defaultValue;
    };

    // --- Hàm chuẩn hóa key (MVU format) ---
    window.k = function(str) {
        return str.replace(/-/g, '\x5F');
    };

    // --- Render danh sách dạng hàng (Row) dùng cho Kinh tế & Quân sự ---
    window.renderRecordRows = function(containerId, dataObject, prefix = '↳ ', cssClass = '') {
        const container = $('#' + containerId);
        container.empty();
        if (!dataObject || typeof dataObject !== 'object') return;
        Object.entries(dataObject).forEach(([key, value]) => {
            if (value !== undefined) {
                const formattedKey = key.replace(/\x5F/g, ' ');
                const row = $('<div class="data-row"><span class="sub-label">' + prefix + ' ' + formattedKey + '</span><span class="data-value ' + cssClass + '">' + value + '</span></div>');
                container.append(row);
            }
        });
    };

    // --- Giao tiếp với AI (Gửi lệnh qua SillyTavern) ---
    window.sendCommandToAI = function(message) {
        try {
            const t = window.parent.document.querySelector("#send_textarea");
            const triggerFunc = window.parent.triggerSlash;
            if (t) {
                const currentText = t.value ? t.value + '\n\n' : '';
                const newPayload = currentText + message;
                if (triggerFunc) { triggerFunc('/setinput ' + newPayload); } 
                else { t.value = newPayload; t.dispatchEvent(new Event("input", { bubbles: true })); }
                t.focus();
            } else if (triggerFunc) {
                triggerFunc('/setinput ' + message);
            } else {
                prompt("Không tìm thấy khung chat. Hãy Copy và dán lệnh sau:", message); 
            }
        } catch (err) {
            console.error("Lỗi đồng bộ Input ST:", err);
            prompt("Đã xảy ra lỗi. Hãy Copy và dán lệnh sau:", message); 
        }
    };

