    window.getClassIcon = function(jobString) {
        const job = String(jobString || '').toLowerCase();

        // 1. HỆ TÀ THẦN (Ưu tiên check trước để không bị nhầm chữ "pháp sư" hay "sư")
        const darkClasses = ['tà giáo', 'tà pháp sư', 'dị đoan', 'huyết sư', 'tử linh'];
        if (darkClasses.some(c => job.includes(c))) return '💀';

        // 2. HỆ TÍN NGƯỠNG
        const faithClasses = ['mục sư', 'thánh kỵ sĩ', 'thẩm phán', 'thần quan', 'tiên tri', 'khổ tu'];
        if (faithClasses.some(c => job.includes(c))) return '⚕️'; // Biểu tượng Thần thánh/Thánh giá/Trị liệu

        // 3. HỆ MẪN TIỆP
        const agilityClasses = ['sát thủ', 'đạo tặc', 'du đãng', 'thi nhân', 'vũ giả', 'bóng tối'];
        if (agilityClasses.some(c => job.includes(c))) return '🗡️';

        // 4. HỆ PHÁP SƯ
        const mageClasses = ['pháp sư', 'áo thuật', 'triệu hồi', 'phụ ma', 'thuật sĩ', 'luyện kim'];
        if (mageClasses.some(c => job.includes(c))) return '🔮';

        // 5. HỆ CHIẾN SĨ
        const warriorClasses = ['kỵ sĩ', 'kiếm sĩ', 'cuồng chiến', 'vệ binh', 'khiên', 'du hiệp'];
        if (warriorClasses.some(c => job.includes(c))) return '⚔️';

        // 6. HỆ ĐẶC BIỆT & XUYÊN KHÔNG DLC (Mặc định nếu không thuộc các phái trên)
        return '🌌'; // Biểu tượng Dải ngân hà / Không gian bí ẩn
