    window.getBuildingInfo = function(name, type) {
        let n = String(name || '').trim().toLowerCase();
        let t = String(type || '').trim().toLowerCase();

        let baseInfo = null;
        for (const key in window.buildingCategoryMap) { 
            if (t.includes(key)) { baseInfo = window.buildingCategoryMap[key]; break; } 
        }
        if (!baseInfo) baseInfo = window.buildingCategoryMap['đặc biệt'];

        for (const key in window.buildingNameMap) { 
            if (n.includes(key)) {
                const specificInfo = window.buildingNameMap[key];
                if (specificInfo.category === baseInfo.category || baseInfo.category === 'đặc biệt') {
                    return { icon: specificInfo.icon, class: baseInfo.class, category: baseInfo.category };
                }
            } 
        }
        return baseInfo;
    };

    window.getWorkforceStats = function() {
        const allVars = window.getMVUVars();
        const status = window.safeGet(allVars, 'stat-data.Lãnh-địa', {});
        const mapData = window.safeGet(allVars, 'stat-data.Bản-đồ', {}); 

        const pop = window.safeGet(status, 'Dân-số', {});
        const buildings = window.safeGet(mapData, 'Công-trình', {}); 

        const maxCrafters = Number(window.safeGet(pop, 'Thợ-thủ-công', 0));
        const maxFarmers = Number(window.safeGet(pop, 'Nông-dân', 0));
        const totalUnemployed = Number(window.safeGet(pop, 'Thất-nghiệp', 0));

        let busyCrafters = 0, busyFarmers = 0;

        if (typeof buildings === 'object') {
            Object.entries(buildings).forEach(([categoryStr, categoryData]) => {
                const catLower = String(categoryStr).toLowerCase().replace(/_/g, ' ').replace(/-/g, ' ');

                // SỬA: Chuyển sang quét Mảng (Array) thay vì Object.entries
                if (Array.isArray(categoryData)) {
                    categoryData.forEach(bData => {
                        let currCap = 0;
                        const workFields = ['Nhân-lực', 'Nhân-khẩu'];
                        for (let field of workFields) {
                            const val = window.safeGet(bData, field);
                            if (typeof val === 'object' && val !== null) {
                                currCap = Number(val['Hiện_tại'] || val['Hiện-tại']) || 0;
                            } else if (typeof val === 'number') {
                                currCap = val;
                            }
                            if (currCap > 0) break;
                        }

                        if (catLower.includes('sản xuất')) busyCrafters += currCap;
                        if (catLower.includes('nông nghiệp')) busyFarmers += currCap;
                    });
                }
            });
        }

        return {
            crafters: { max: maxCrafters, busy: busyCrafters, free: Math.max(0, maxCrafters - busyCrafters) },
            farmers: { max: maxFarmers, busy: busyFarmers, free: Math.max(0, maxFarmers - busyFarmers) },
            unemployed: { free: totalUnemployed } 
        };
    };

