    // --- Hàm đọc Pháp lệnh để lấy mức lương quân đội ---
    window.getMilitarySalaryFromDecrees = function() {
        const allVars = window.getMVUVars();
        // Sửa giá trị mặc định thành []
        const decrees = window.safeGet(allVars, 'stat-data.Pháp-lệnh.Danh-sách-chi-tiết', []);
        let foundSalaryInGold = null, originalText = "", decreeName = "";

        // Chuyển từ Object.entries sang quét Mảng (Array)
        if (Array.isArray(decrees)) {
            decrees.forEach(d => {
                const name = String(window.safeGet(d, 'Tên-pháp-lệnh', ''));
                const status = String(window.safeGet(d, 'Trạng-thái', '')).toLowerCase();
                const content = String(window.safeGet(d, 'Nội-dung', '')).toLowerCase();
                if (status.includes('hiệu lực') && (name.toLowerCase().includes('lương') || content.includes('quân phí') || content.includes('chiêu mộ'))) {
                    const match = content.match(/(\d+(?:\.\d+)?)\s*(vàng|kim long|bạc|ngân lộc|đồng|đồng tinh)/i);
                    if (match) {
                        let val = parseFloat(match[1]), unit = match[2].toLowerCase();
                        originalText = match[0];
                        if (unit.includes('bạc') || unit.includes('ngân lộc')) foundSalaryInGold = val / 100;
                        else if (unit.includes('đồng') || unit.includes('đồng tinh')) foundSalaryInGold = val / 10000;
                        else foundSalaryInGold = val;
                        decreeName = name;
                    }
                }
            });
        }
        return { salaryInGold: foundSalaryInGold, originalText: originalText, name: decreeName };
    };

