    // Tải dữ liệu từ LocalStorage lên UI
    window.loadNSFWStatsFromMemory = function() {
        Object.keys(nsfwKeysMap).forEach(htmlId => {
            const savedData = localStorage.getItem('NSFW_' + htmlId);
            if (savedData && $('#' + htmlId).length) {
                $('#' + htmlId).text(savedData);
            }
        });
    };

    // Hàm quét tin nhắn AI
    window.scanChatForNSFWStats = function() {
        try {
            window.loadNSFWStatsFromMemory();
            const chatMessages = window.parent.document.querySelectorAll('.mes_text');
            if (!chatMessages || chatMessages.length === 0) return;

            for (let i = 0; i < chatMessages.length; i++) {
                const text = chatMessages[i].textContent;

                if (text.includes('[HIDDEN_STATUS]')) {
                    // Cắt lấy toàn bộ khối Text bên trong thẻ Hidden
                    const blockMatch = text.match(/\[HIDDEN_STATUS\]([\s\S]*?)\[\/HIDDEN_STATUS\]/i);
                    if (!blockMatch) continue;
                    const content = blockMatch[1];

                    // Tạo chuỗi điểm chặn Regex
                    const allKeywords = Object.values(nsfwKeysMap).join('|');

                    // Quét tìm từng chỉ số một và lưu vào Đệm
                    Object.entries(nsfwKeysMap).forEach(([htmlId, keyName]) => {
                        const regexStr = `(?:${keyName})\\s*[:：]\\s*([\\s\\S]*?)(?=\\s*(?:${allKeywords})\\s*[:：]|$)`;
                        const regex = new RegExp(regexStr, 'i');

                        const match = content.match(regex);
                        if (match && match[1]) {
                            const parsedText = match[1].trim();
                            if (parsedText !== '') {
                                $('#' + htmlId).text(parsedText);
                                localStorage.setItem('NSFW_' + htmlId, parsedText);
                            }
                        }
                    });
                }
            }
        } catch (e) {
            console.error("Lỗi khi quét bảng phân tích sinh lý:", e);
        }
    };

    // --- Hành động: Chiêu mộ quân đội ---
    window.stRecruitTroops = function() {
        const allVars = window.getMVUVars();
        const mapData = window.safeGet(allVars, 'stat-data.Bản-đồ', {});
        const pop = window.safeGet(allVars, 'stat-data.Lãnh-địa.Dân-số', {});
        const eco = window.safeGet(allVars, 'stat-data.Lãnh-địa.Kinh-tế', {});
        const militaryBuildings = window.safeGet(mapData, 'Công-trình.Quân_sự', {});

        let availableBarracks = [];
        if (typeof militaryBuildings === 'object') {
            Object.entries(militaryBuildings).forEach(([bName, bData]) => {
                let curr = Number(window.safeGet(bData, 'Binh-lính.Hiện-tại', 0));
                let max = Number(window.safeGet(bData, 'Binh-lính.Tối-đa', 0));
                let unitType = window.safeGet(bData, 'Huấn-luyện', 'Bộ binh');

                if (curr < max) {
                    availableBarracks.push({
                        name: bName,
                        type: unitType,
                        free: max - curr,
                        coord: window.safeGet(bData, 'Tọa-độ', '?,?')
                    });
                }
            });
        }

        if (availableBarracks.length === 0) {
            return alert("❌ Không tìm thấy doanh trại nào còn chỗ trống! Lãnh chúa cần xây thêm hoặc nâng cấp trại lính.");
        }

        let listStr = "🏰 DANH SÁCH TRẠI LÍNH CÒN CHỖ:\n";
        availableBarracks.forEach((b, i) => {
            listStr += `${i + 1}. ${b.name} [${b.type}] (Còn trống: ${b.free} chỗ)\n`;
        });

        const choice = prompt(listStr + "\n👉 Nhập SỐ THỨ TỰ trại muốn đưa quân vào:", "1");
        if (!choice || isNaN(parseInt(choice)) || !availableBarracks[parseInt(choice) - 1]) return;

        const targetBarrack = availableBarracks[parseInt(choice) - 1];

        const decreeInfo = window.getMilitarySalaryFromDecrees();
        let costPerSoldierGold = 0, displayCostStr = "";

        if (decreeInfo.salaryInGold !== null) {
            costPerSoldierGold = decreeInfo.salaryInGold;
            displayCostStr = decreeInfo.originalText;
        } else {
            const userInput = prompt(`📜 CHƯA CÓ PHÁP LỆNH QUÂN LƯƠNG!\nNhập mức phí cấp cho 1 tân binh (VD: 25 Bạc, 1 Vàng):`, "25 Bạc");
            if (!userInput) return;
            const match = userInput.match(/(\d+(?:\.\d+)?)\s*(vàng|bạc|đồng|kim long|ngân lộc|đồng tinh)?/i);
            if (!match) return alert("❌ Sai cú pháp!");
            let val = parseFloat(match[1]), unit = (match[2] || "vàng").toLowerCase();
            displayCostStr = val + " " + unit;
            costPerSoldierGold = unit.includes('bạc') || unit.includes('ngân lộc') ? val / 100 : (unit.includes('đồng') ? val / 10000 : val);
        }

        const gold = Number(window.safeGet(eco, 'Vàng-tồn-kho', 0));
        const unemployed = Number(window.safeGet(pop, 'Thất-nghiệp', 0));
        const maxCapacity = targetBarrack.free;
        const maxAffordable = costPerSoldierGold > 0 ? Math.floor(gold / costPerSoldierGold) : unemployed;

        const finalLimit = Math.min(maxCapacity, unemployed, maxAffordable);

        if (finalLimit <= 0) return alert("❌ Không đủ điều kiện (Dân rảnh, Tiền hoặc Chỗ trống)!");

        const amountStr = prompt(`🗡️ CHIÊU MỘ VÀO: ${targetBarrack.name}\n\n- Chỗ trống tại trại: ${maxCapacity}\n- Đinh tráng rảnh rỗi: ${unemployed}\n- Chi phí: ${displayCostStr}/người\n\n👉 Nhập số lượng chiêu mộ (Tối đa ${finalLimit}):`, finalLimit);
        const amount = parseInt(amountStr);

        if (isNaN(amount) || amount <= 0 || amount > finalLimit) return alert("❌ Số lượng không hợp lệ!");

        const totalCostGold = Math.round((amount * costPerSoldierGold) * 10000) / 10000;

        if (confirm(`Xác nhận chi ${totalCostGold} Vàng để đưa ${amount} quân [${targetBarrack.type}] vào [${targetBarrack.name}]?`)) {
            const zodUnitKey = targetBarrack.type.replace(/ /g, '_');
            let extraAction = totalCostGold > 0 ? `\n2. TRỪ ${totalCostGold} Vàng tại [Kinh_tế.Vàng_tồn_kho] (Phí: ${amount} x ${displayCostStr}).` : "";

            let msg = `[LỆNH ĐIỀU BINH CHÍNH XÁC]\nLãnh chúa chiêu mộ ${amount} tân binh và CHỈ ĐỊNH trực tiếp vào [${targetBarrack.name}]. \n\nBẮT BUỘC THỰC HIỆN ĐỒNG BỘ CÁC BIẾN SAU:\n1. TRỪ ${amount} tại [Dân_số.Thất_nghiệp].${extraAction}\n3. CỘNG ${amount} vào [Quân_sự.Binh_lực_thường_trực].\n4. CỘNG ${amount} vào [Quân_sự.Chi_tiết_binh_chủng.${zodUnitKey}].\n5. CẬP NHẬT TRỰC TIẾP: Cộng ${amount} vào tham số [Bản_đồ.Công_trình.Quân_sự.${targetBarrack.name}.Binh_lính.Hiện_tại].\n\nTuyệt đối không phân bổ vào trại khác ngoài trại đã chỉ định.`;

            if (!decreeInfo.salaryInGold) {
                if (!window.stDecreeBuffer) window.stDecreeBuffer = { new: [], modified: [], abolished: [] };
                window.stDecreeBuffer.new.push({ type: 'Pháp lệnh Quân sự', name: 'Đạo luật Quân phí Tân binh', content: `Ngân khố cấp ${displayCostStr} cho mỗi đinh tráng gia nhập quân đội (Tương đương ${costPerSoldierGold} Vàng).` });
                if (typeof window.stRenderPendingList === 'function') window.stRenderPendingList();
                msg += `\n\n[HÀNH CHÍNH]: Lãnh chúa quy định phí là ${displayCostStr}/người. Đã lưu dự thảo Pháp lệnh.`;
            }

            window.sendCommandToAI(msg);
            alert(`✅ Lệnh đã ban! ${amount} quân đang tiến về ${targetBarrack.name}.`);
        }
    };

