    // --- Kiểm tra điều kiện vị trí địa lý ---
    window.checkAdjacency = function(coordStr, type, name) {
        const allVars = window.getMVUVars();
        const mapData = window.safeGet(allVars, 'stat-data.Bản-đồ', {});
        const outsideAreas = window.safeGet(mapData, 'Khu-vực-ngoài-lãnh-thổ', {});
        const parts = coordStr.split(',');
        const cx = parseInt(parts[0]); const cy = parseInt(parts[1]);
        let hasWater = false, hasForest = false, hasMine = false, hasDanger = false, dangerName = "";

        for(let dx = -1; dx <= 1; dx++) {
            for(let dy = -1; dy <= 1; dy++) {
                if (dx === 0 && dy === 0) continue; 
                const checkCoord = (cx + dx) + ',' + (cy + dy);

                Object.entries(outsideAreas).forEach(([areaName, data]) => {
                    if (window.safeGet(data, 'Tọa-độ') === checkCoord) {
                        const tStr = String(window.safeGet(data, 'Loại')).toLowerCase();
                        const stStr = String(window.safeGet(data, 'Trạng-thái')).toLowerCase();
                        const nStr = String(areaName).toLowerCase();

                        if (tStr.includes('rừng') || nStr.includes('rừng')) hasForest = true;
                        if (tStr.includes('nước') || tStr.includes('suối') || tStr.includes('hồ') || nStr.includes('suối') || nStr.includes('hồ')) hasWater = true;
                        if (tStr.includes('mỏ') || tStr.includes('khoáng') || nStr.includes('mỏ')) hasMine = true;

                        if (stStr.includes('nguy hiểm') || tStr.includes('quái vật') || tStr.includes('cướp') || tStr.includes('địch') || tStr.includes('tặc') || nStr.includes('cướp') || nStr.includes('quái vật') || nStr.includes('tặc')) {
                            hasDanger = true; dangerName = areaName;
                        }
                    }
                });

                const threats = window.safeGet(allVars, 'stat-data.Lãnh-địa.Mối-đe-dọa', {});
                Object.entries(threats).forEach(([tName, tData]) => {
                    if (window.safeGet(tData, 'Vị-trí') === checkCoord) { hasDanger = true; dangerName = tName; }
                });

                const resData = window.safeGet(allVars, 'stat-data.Lãnh-địa.Tài-nguyên', {});
                ['Rừng-rậm', 'Mạch-khoáng', 'Nguồn-nước'].forEach(cat => {
                    Object.entries(window.safeGet(resData, cat, {})).forEach(([rName, rObj]) => {
                         if (window.safeGet(rObj, 'Vị-trí') === checkCoord) {
                             const threat = String(window.safeGet(rObj, 'Mối-đe-dọa', '')).trim();
                             if (threat && !['không có', 'an toàn', 'không'].includes(threat.toLowerCase())) {
                                 hasDanger = true; dangerName = threat;
                             }
                         }
                    });
                });
            }
        }

        let html = ""; let bgColor = "rgba(45, 80, 22, 0.1)"; let borderColor = "#2D5016";
        window.stCurrentGeoWarning = false;
        const nLower = String(name).toLowerCase(); const tLower = String(type).toLowerCase();

        if (tLower.includes('sản xuất')) {
            if (nLower.includes('gỗ') || nLower.includes('tiều phu')) {
                if (hasForest) html = "✅ Nằm sát Rừng rậm. Đủ điều kiện khai thác.";
                else { html = "⚠️ LỖI VỊ TRÍ: Xung quanh không có Rừng! Sản lượng sẽ bằng 0."; bgColor = "rgba(139, 35, 35, 0.1)"; borderColor = "#8B2323"; window.stCurrentGeoWarning = true; }
            } else if (nLower.includes('mỏ') || nLower.includes('khoáng')) {
                if (hasMine) html = "✅ Nằm sát Mạch khoáng. Đủ điều kiện khai khoáng.";
                else { html = "⚠️ LỖI VỊ TRÍ: Xung quanh không có Mỏ quặng! Sản lượng sẽ bằng 0."; bgColor = "rgba(139, 35, 35, 0.1)"; borderColor = "#8B2323"; window.stCurrentGeoWarning = true; }
            }
        }
        if (tLower.includes('nông nghiệp') || tLower.includes('dân cư') || tLower.includes('thương mại')) {
            if (hasWater) {
                html += (html ? "<br>" : "") + "💧 Lợi thế Thủy lợi: Nằm sát nguồn nước, tăng 20% hiệu suất.";
                if (!window.stCurrentGeoWarning) { bgColor = "rgba(45, 80, 134, 0.1)"; borderColor = "#2D5086"; } 
            }
        }
        if (hasDanger) {
            html += (html ? "<br>" : "") + `🚨 BÁO ĐỘNG: Cạnh sào huyệt của [${dangerName}]! Nguy cơ bị tàn phá rất cao!`;
            bgColor = "rgba(139, 35, 35, 0.1)"; borderColor = "#8B2323"; window.stCurrentGeoWarning = true;
        }

        if (!html) return false;
        $('#build-geo-report').html(`<div style="background: ${bgColor}; border: 1px dashed ${borderColor}; padding: 8px; border-radius: 4px; color: ${borderColor === '#8B2323' ? '#8B2323' : '#2C1810'};"><b>📡 Phân tích Vị trí:</b><br>${html}</div>`);
        return true;
    }

    // --- Kiểm tra nhân công để xây dựng ---
    window.checkWorkforceAvailability = function(tier, requiredAmount) {
        const stats = window.getWorkforceStats();
        let deficit = 0;
        if (tier === 'Nghệ nhân' || tier === 'Lành nghề') {
            const totalCrafters = stats.crafters.free + stats.crafters.busy;
            if (totalCrafters < requiredAmount) return { ok: false, msg: `❌ Tổng Thợ thủ công chỉ có ${totalCrafters}, không đủ ${requiredAmount} người!\n👉 Hãy chọn Thợ phổ thông hoặc Thất nghiệp!` };
            if (stats.crafters.free < requiredAmount) {
                deficit = requiredAmount - stats.crafters.free;
                return { ok: true, needConfirm: true, pullAmount: deficit, pullCategory: 'Sản xuất', msg: `⚠️ THIẾU THỢ RẢNH RỖI!\nCần ${requiredAmount} người nhưng chỉ có ${stats.crafters.free} thợ rảnh.\n👉 Hệ thống sẽ TỰ ĐỘNG CƯỠNG CHẾ ${deficit} thợ đang làm việc đi xây dựng.\nSản lượng kinh tế tháng này sẽ giảm. Ngài có chắc chắn muốn điều động?` };
            }
        } else if (tier === 'Phổ thông') {
            const totalFarmers = stats.farmers.free + stats.farmers.busy;
            if (totalFarmers < requiredAmount) return { ok: false, msg: `❌ Tổng Nông dân chỉ có ${totalFarmers}, không đủ ${requiredAmount} người!\n👉 Hãy chọn nhóm Thất nghiệp!` };
            if (stats.farmers.free < requiredAmount) {
                deficit = requiredAmount - stats.farmers.free;
                return { ok: true, needConfirm: true, pullAmount: deficit, pullCategory: 'Nông nghiệp', msg: `⚠️ THIẾU NÔNG DÂN RẢNH RỖI!\nCần ${requiredAmount} người nhưng chỉ có ${stats.farmers.free} nông dân rảnh.\n👉 Hệ thống sẽ TỰ ĐỘNG CƯỠNG CHẾ ${deficit} nông dân đang làm ruộng đi xây dựng.\nLương thực tháng này sẽ giảm sút. Ngài có chắc chắn muốn điều động?` };
            }
        } else if (tier === 'Thất nghiệp') {
            if (stats.unemployed.free < requiredAmount) return { ok: false, msg: `❌ Lãnh địa cạn kiệt nhân lực!\nNgay cả Thất nghiệp cũng chỉ còn ${stats.unemployed.free} người (Cần ${requiredAmount}).\n👉 Hãy xây dựng thêm nhà dân để tăng thêm dân số!` };
        }
        return { ok: true, needConfirm: false };
    }

    // --- Tối ưu phép tính: Xóa bỏ hàm mul(), dùng phép toán nguyên thủy ---
    window.calculateEconomics = function(name, type, isUpgrade, currentLevelStr, desiredDays, workerTierStr, size = 1) {
        const bInfo = window.getBuildingInfo(name, type);
        const cat = bInfo.category;
        const searchStr = (String(name) + ' ' + String(type)).toLowerCase();
        const isCapital = searchStr.includes('thủ phủ') || searchStr.includes('lãnh chúa') || bInfo.class === 'lord';

        let base = { goldAdmin: 200, wood: 500, stone: 300, iron: 50, food: 200 };
        if (isCapital) base = { goldAdmin: 5000, wood: 8000, stone: 15000, iron: 5000, food: 10000 };
        else if (cat === 'quân sự') base = { goldAdmin: 500, wood: 1200, stone: 4000, iron: 1500, food: 800 };
        else if (cat === 'sản xuất' || cat === 'thương mại') base = { goldAdmin: 1000, wood: 2500, stone: 1200, iron: 400, food: 600 };
        else if (cat === 'tôn giáo' || cat === 'hành chính') base = { goldAdmin: 2000, wood: 3000, stone: 6000, iron: 1000, food: 1500 };
        else if (cat === 'nông nghiệp') base = { goldAdmin: 100, wood: 300, stone: 100, iron: 50, food: 100 };

        const scaleMulti = size * size; 
        let level = parseInt(String(currentLevelStr).replace(/\D/g, '')) || 1;
        let upgradeMulti = isUpgrade ? (isCapital ? (level + 1) * 3 : (level + 1) * 1.5) : 1; 

        const finalMat = { 
            wood: Math.floor(base.wood * scaleMulti * upgradeMulti), 
            stone: Math.floor(base.stone * scaleMulti * upgradeMulti), 
            iron: Math.floor(base.iron * scaleMulti * upgradeMulti), 
            food: Math.floor(base.food * scaleMulti * upgradeMulti) 
        };

        const tier = window.workerTiers[workerTierStr] || window.workerTiers['Lành nghề'];
        const days = Math.max(1, parseInt(desiredDays) || 7);
        const totalWorkload = finalMat.wood + (finalMat.stone * 2) + (finalMat.iron * 4);
        const reqWorkers = Math.max(1, Math.ceil(totalWorkload / (tier.capacity * days)));
        const totalLaborCost = Math.ceil(reqWorkers * tier.dailyWage * days);
        const baseAdminGold = Math.floor(base.goldAdmin * scaleMulti * upgradeMulti);
        const dailyAdminFee = Math.max(1, Math.floor(baseAdminGold / 7)); 
        const actualAdminGold = dailyAdminFee * days;
        const finalTotalGold = actualAdminGold + totalLaborCost;

        const costObj = { gold: finalTotalGold, wood: finalMat.wood, stone: finalMat.stone, iron: finalMat.iron, food: finalMat.food };
        const costHtml = `<div style="margin-bottom: 4px;">💰 <b>Vàng: ${finalTotalGold}</b> <span style="font-size:0.7em; color:#8B6914;">(Lương: ${totalLaborCost} + Phí: ${actualAdminGold})</span></div><div style="margin-bottom: 4px; font-size: 0.9em;">🌳 Gỗ: ${finalMat.wood} | ⛰ Đá: ${finalMat.stone} | ⛏️ Sắt: ${finalMat.iron}</div><div style="color: #2D5016; border-top: 1px dashed #C9A227; padding-top: 4px; margin-top: 4px; font-size: 0.95em;">👷 Điều động: <b>${reqWorkers} ${workerTierStr}</b></div>`;
        return { costObj: costObj, workers: reqWorkers, days: days, tierName: workerTierStr, html: costHtml };
    }

    // --- Kiểm tra tồn kho vật tư ---
    window.checkResources = function(costObj) {
        const allVars = window.getMVUVars();
        const status = window.safeGet(allVars, 'stat-data.Lãnh-địa', {});
        const eco = window.safeGet(status, 'Kinh-tế', {});
        const inv = window.safeGet(status, 'Vật-tư-kho', {});
        const curr = {
            gold: Number(window.safeGet(eco, 'Vàng-tồn-kho', 0)) || 0,
            wood: Number(window.safeGet(inv, 'Gỗ', 0)) || 0,
            stone: Number(window.safeGet(inv, 'Đá', 0)) || 0,
            iron: Number(window.safeGet(inv, 'Quặng-sắt', 0)) || 0,
            food: Number(window.safeGet(inv, 'Lương-thực', 0)) || 0
        };
        let missing = [];
        if (curr.gold < costObj.gold) missing.push('- 💰 Vàng (Cần: ' + costObj.gold + ' | Có: ' + curr.gold + ')');
        if (curr.wood < costObj.wood) missing.push('- 🌳 Gỗ (Cần: ' + costObj.wood + ' | Có: ' + curr.wood + ')');
        if (curr.stone < costObj.stone) missing.push('- ⛰ Đá (Cần: ' + costObj.stone + ' | Có: ' + curr.stone + ')');
        if (curr.iron < costObj.iron) missing.push('- ⛏️ Sắt (Cần: ' + costObj.iron + ' | Có: ' + curr.iron + ')');
        return { ok: missing.length === 0, msg: "❌ KHO BẠC KHÔNG ĐỦ KHỞI CÔNG:\n\n" + missing.join("\n") };
    }

    // --- Kiểm tra Cây công nghệ quân sự ---
    window.checkMilitaryTechTree = function() {
        const allVars = window.getMVUVars();
        const mapData = window.safeGet(allVars, 'stat-data.Bản-đồ', {});
        const heroes = window.safeGet(allVars, 'stat-data.Anh-hùng', {});
        const buildings = window.safeGet(mapData, 'Công-trình', {});

        let hasAcademy = false, hasStable = false, hasLogistics = false;
        let hasIntelHero = false, hasLvl2Military = false;
        let hasAnyHero = Object.keys(heroes).length > 0;

        Object.values(heroes).forEach(h => {
            const traits = String(window.safeGet(h, 'Sở-trường', '')).toLowerCase();
            const job = String(window.safeGet(h, 'Chức-nghiệp', '')).toLowerCase();
            if (traits.includes('tình báo') || traits.includes('trinh sát') || traits.includes('ẩn nấp') || job.includes('trinh sát')) hasIntelHero = true;
        });

        Object.entries(buildings).forEach(([catStr, catData]) => {
            const cat = catStr.replace(/-/g, '_');
            if (typeof catData === 'object') {
                Object.entries(catData).forEach(([bName, bData]) => {
                    const nameLower = String(bName).toLowerCase();
                    if (nameLower.includes('học viện')) hasAcademy = true;
                    if (nameLower.includes('chuồng ngựa')) hasStable = true;
                    if (cat === 'Hậu_cần' && nameLower.includes('kho hậu phương')) hasLogistics = true;
                    if (cat === 'Quân_sự' && Number(window.safeGet(bData, 'Cấp-độ', 1)) >= 2) hasLvl2Military = true;
                });
            }
        });

        let allowed = [ {val: 'Bộ binh', label: '⚔️ Bộ binh (Mặc định)'}, {val: 'Cung thủ', label: '🏹 Cung thủ (Mặc định)'} ];
        if (hasAcademy) allowed.push({val: 'Pháp sư', label: '🔮 Pháp sư (Y/c Học viện)'});
        if (hasStable) allowed.push({val: 'Kỵ binh', label: '🐎 Kỵ binh (Y/c Chuồng ngựa)'});
        if (hasLogistics) allowed.push({val: 'Hỗ trợ hậu cần', label: '📦 Hậu cần (Y/c Kho hậu phương)'});
        if (hasIntelHero) allowed.push({val: 'Trinh sát', label: '👁️ Trinh sát (Y/c Tướng tình báo)'});
        if (hasLvl2Military && hasAnyHero) allowed.push({val: 'Đơn vị đặc chủng', label: '🦇 Đặc chủng (Y/c Trại Cấp 2 + Tướng)'});

        return allowed;
    }

    // --- Biến toàn cục Map Engine ---
    const gridSize = 30;
    window.currentCenterX = 500; 
    window.currentCenterY = 500;
    window.isBuildMode = false;
    let isDraggingMap = false;
    let startMapX, startMapY, scrollMapLeft, scrollMapTop;

    // --- Logic kéo thả Bản đồ (Drag & Drop) ---
    $(document).on('mousedown', '#map-scroll', function(e) {
        if (e.target.closest('.map-building') || e.target.closest('.toolbar-btn') || e.target.closest('input') || e.target.closest('select')) return;
        startMapX = e.pageX; startMapY = e.pageY;
        if (window.isBuildMode && window.buildPathStart) return; 
        isDraggingMap = true;
        scrollMapLeft = $(this).scrollLeft();
        scrollMapTop = $(this).scrollTop();
        $(this).css('cursor', 'grabbing');
    });

    $(document).on('mousemove', '#map-scroll', function(e) {
        if (isDraggingMap) {
            e.preventDefault();
            $(this).scrollLeft(scrollMapLeft - (e.pageX - startMapX));
            $(this).scrollTop(scrollMapTop - (e.pageY - startMapY));
        } else if (window.isBuildMode) {
            const scroller = $(this);
            const rect = this.getBoundingClientRect();
            const gridX = Math.floor((e.clientX - rect.left + scroller.scrollLeft()) / gridSize);
            const gridY = Math.floor((e.clientY - rect.top + scroller.scrollTop()) / gridSize);
            const coordStr = gridX + ',' + gridY;

            if (window.stExploredSet && window.stExploredSet.has(coordStr)) {
                const size = parseInt($('#build-input-size').val()) || 1;
                const offset = -Math.floor((size - 1) / 2) * gridSize;

                $('#build-cursor').css({ 
                    left: (gridX * gridSize + offset) + 'px', 
                    top: (gridY * gridSize + offset) + 'px', 
                    width: (size * gridSize) + 'px',
                    height: (size * gridSize) + 'px',
                    display: 'flex' 
                }).text(coordStr);

                if (window.buildPathStart) {
                    $('.path-preview-cell').remove();
                    const startParts = window.buildPathStart.split(',');
                    const startX = parseInt(startParts[0]); const startY = parseInt(startParts[1]);

                    let minX = Math.min(startX, gridX), maxX = Math.max(startX, gridX);
                    let minY = Math.min(startY, gridY), maxY = Math.max(startY, gridY);

                    if (Math.abs(gridX - startX) > Math.abs(gridY - startY)) minY = maxY = startY; 
                    else minX = maxX = startX;

                    for(let x = minX; x <= maxX; x++) {
                        for(let y = minY; y <= maxY; y++) {
                            if (x === startX && y === startY) continue;
                            const cell = $('<div class="path-preview-cell"></div>');
                            cell.css({ left: (x * gridSize) + 'px', top: (y * gridSize) + 'px', width: gridSize + 'px', height: gridSize + 'px' });
                            $('#map-world-canvas').append(cell);
                        }
                    }
                }
            } else {
                $('#build-cursor').hide();
                $('.path-preview-cell').remove();
            }
        }
    });

    $(document).on('mouseleave mouseup', '#map-scroll', function() { 
        if (isDraggingMap) {
            isDraggingMap = false; 
            $(this).css('cursor', window.isBuildMode ? 'crosshair' : 'grab');
            window.currentCenterX = Math.floor(($(this).scrollLeft() + ($(this).width() / 2)) / gridSize);
            window.currentCenterY = Math.floor(($(this).scrollTop() + ($(this).height() / 2)) / gridSize);
        }
    });

    // --- Xử lý sự kiện click ô đất Bản đồ ---
    $(document).on('click', '#map-scroll', function(e) {
        if (!window.isBuildMode || window.isDraggingMap) return;
        if (Math.abs(e.pageX - startMapX) > 5 || Math.abs(e.pageY - startMapY) > 5) return;

        const scroller = $(this);
        const rect = this.getBoundingClientRect();
        const gridX = Math.floor((e.clientX - rect.left + scroller.scrollLeft()) / gridSize);
        const gridY = Math.floor((e.clientY - rect.top + scroller.scrollTop()) / gridSize);
        const coordStr = gridX + ',' + gridY;

        if (window.stExploredSet && window.stExploredSet.has(coordStr)) {
            if (window.buildPathStart) {
                if (window.buildPathStart === coordStr) return; 
                const startParts = window.buildPathStart.split(',');
                const startX = parseInt(startParts[0]); const startY = parseInt(startParts[1]);

                if (startX !== gridX && startY !== gridY) return alert("⚠️ Lãnh chúa chỉ có thể quy hoạch tường/đường theo trục thẳng (Ngang hoặc Dọc)!");

                const rangeStr = window.buildPathStart + ' - ' + coordStr;
                window.buildPathStart = null;
                $('.path-preview-cell').remove();

                $('#map-build-panel').hide();
                window.showPathBuildPanel(rangeStr, startX, startY, gridX, gridY);
            } else {
                window.stCurrentSelectedCoord = coordStr;
                const menu = $('#build-action-menu');
                menu.css({ left: (gridX * gridSize + gridSize/2) + 'px', top: (gridY * gridSize) + 'px' }).fadeIn(150);
                $('#map-world-canvas').append(menu);
            }
        }
    });

    // --- State Variables cho Quy hoạch ---
    window.buildPathStart = null;
    window.stCurrentPathLength = 0;
    window.stCurrentSelectedCoord = null; 
    window.stCurrentSelectedName = null;
    window.stCurrentCostRaw = null; 
    window.stCurrentWorkers = 0; 
    window.stCurrentDays = 0; 
    window.stCurrentTier = ""; 
    window.stCurrentCostString = "";

    function saveCostData(data) {
        window.stCurrentCostRaw = data.costObj;
        window.stCurrentWorkers = data.workers;
        window.stCurrentDays = data.days;
        window.stCurrentTier = data.tierName;
        window.stCurrentCostString = `Vàng: ${data.costObj.gold}, Gỗ: ${data.costObj.wood}, Đá: ${data.costObj.stone}, Sắt: ${data.costObj.iron}`;
    }

    // --- Các hàm UI Control cho Bản đồ ---
    window.toggleBuildMode = function() {
        if (window.buildPathStart) { window.cancelPathBuild(); return; } 
        window.isBuildMode = !window.isBuildMode;
        const btn = $('#btn-build-mode');
        if (window.isBuildMode) {
            btn.addClass('build-mode-active').html('<span>❌</span> <span>Hủy Quy hoạch</span>');
            $('#map-scroll').css('cursor', 'crosshair');
            if ($('#build-cursor').length === 0) $('#map-world-canvas').append('<div id="build-cursor"></div>');
        } else {
            btn.removeClass('build-mode-active').html('<span>🔨</span> <span>Quy hoạch</span>');
            $('#map-scroll').css('cursor', 'grab');
            $('#build-cursor').hide();
            $('#build-action-menu').hide();
        }
    };

    window.showBuildPanel = function(coord) {
        window.stCurrentSelectedCoord = coord;
        $('#build-coord').text(coord);
        $('#build-input-name').val('');
        window.updateBuildCost();
        $('#map-info-panel').hide();
        $('#map-build-panel').slideDown(200);
    };

    window.startNormalBuild = function() {
        $('#build-action-menu').hide();
        window.isBuildMode = false; 
        $('#btn-build-mode').removeClass('build-mode-active').html('<span>🔨</span> <span>Quy hoạch</span>');
        $('#build-cursor').hide();
        window.showBuildPanel(window.stCurrentSelectedCoord);
    };

    window.startPathBuild = function() {
        $('#build-action-menu').hide();
        window.buildPathStart = window.stCurrentSelectedCoord;
        $('#build-cursor').css('border-color', '#FF9900'); 
    };

    window.cancelPathBuild = function() {
        window.buildPathStart = null;
        $('.path-preview-cell').remove();
        $('#map-path-build-panel').fadeOut();
        $('#build-cursor').css('border-color', '#7CFC00');
    };

    window.showPathBuildPanel = function(rangeStr, x1, y1, x2, y2) {
        window.isBuildMode = false; 
        $('#btn-build-mode').removeClass('build-mode-active').html('<span>🔨</span> <span>Quy hoạch</span>');
        $('#build-cursor').hide();

        $('#build-path-range').text(rangeStr);
        window.stCurrentPathLength = Math.max(Math.abs(x2 - x1), Math.abs(y2 - y1)) + 1; 
        $('#build-path-length').text(window.stCurrentPathLength);
        $('#build-path-name').val('');
        window.updatePathBuildCost();
        $('#map-info-panel, #map-build-panel').hide();
        $('#map-path-build-panel').slideDown(200);
        window.stCurrentSelectedCoord = rangeStr; 
    };

    window.updateBuildCost = function() {
        let rawName = $('#build-input-name').val();
        const type = $('#build-select-type').val();
        const days = $('#build-input-days').val();
        const tier = $('#build-input-tier').val();
        const size = parseInt($('#build-input-size').val()) || 1; 

        if (type === 'Quân sự') {
            if (!$('#build-military-type').is(':visible')) {
                $('#build-military-type').show();
                $('#build-input-name').attr('placeholder', 'Tên riêng (VD: Bắc Phong)...');
                const allowed = window.checkMilitaryTechTree();
                $('#build-military-type').empty();
                allowed.forEach(opt => $('#build-military-type').append(`<option value="${opt.val}">${opt.label}</option>`));
            }
            if ($('#build-military-type').val() === 'Đơn vị đặc chủng') {
                if (!$('#build-military-hero').is(':visible')) {
                    $('#build-military-hero').show();
                    const heroes = window.safeGet(window.getMVUVars(), 'stat-data.Anh-hùng', {});
                    $('#build-military-hero').empty();
                    Object.entries(heroes).forEach(([hName, hData]) => {
                        $('#build-military-hero').append(`<option value="${hName}" data-class="${window.safeGet(hData, 'Chức-nghiệp', '')}">Giao Tướng: ${hName} (${window.safeGet(hData, 'Chức-nghiệp', '')})</option>`);
                    });
                }
            } else {
                $('#build-military-hero').hide();
            }
        } else {
            $('#build-military-type, #build-military-hero').hide();
            $('#build-input-name').attr('placeholder', 'Tên công trình mới...');
        }

        if (rawName && type) {
            let evalName = type === 'Quân sự' ? ( $('#build-military-type').val() === 'Đơn vị đặc chủng' ? `Trại đặc chủng ${rawName}` : `Trại ${$('#build-military-type').val().toLowerCase()} ${rawName}` ) : rawName;

            const data = window.calculateEconomics(evalName, type, false, 1, days, tier, size);
            saveCostData(data); $('#build-cost-val').html(data.html);

            if (window.checkAdjacency(window.stCurrentSelectedCoord, type, evalName)) $('#build-geo-report').slideDown(150);
            else $('#build-geo-report').hide();
        } else {
            window.stCurrentCostRaw = null; $('#build-cost-val').html("Vui lòng nhập tên và loại..."); $('#build-geo-report').hide();
        }
    };

    window.stExecuteBuild = function() {
        if (!window.stCurrentCostRaw) return;

        const allVars = window.getMVUVars();
        const mapData = window.safeGet(allVars, 'stat-data.Bản-đồ', {});
        let isOccupied = false;

        // Quét mảng Đang xây dựng
        const ucArr = window.safeGet(mapData, 'Đang-xây-dựng', []);
        if (Array.isArray(ucArr)) {
             ucArr.forEach(b => {
                 if (window.safeGet(b, 'Tọa-độ') === window.stCurrentSelectedCoord) isOccupied = true;
             });
        }

        // Quét các mảng Công trình
        const bGroup = window.safeGet(mapData, 'Công-trình', {});
        if (typeof bGroup === 'object') {
             Object.values(bGroup).forEach(catArray => {
                 if (Array.isArray(catArray)) {
                     catArray.forEach(b => {
                         if (window.safeGet(b, 'Tọa-độ') === window.stCurrentSelectedCoord) isOccupied = true;
                     });
                 }
             });
        }

        if (isOccupied) return alert("❌ LỖI QUY HOẠCH: Tọa độ này đã có công trình tồn tại hoặc đang được thi công. Vui lòng chọn một ô đất trống khác!");
        if (window.stCurrentGeoWarning && !confirm("⚠️ Vị trí không hợp lý. Tiếp tục?")) return;

        const resCheck = window.checkResources(window.stCurrentCostRaw);
        if (!resCheck.ok) return alert(resCheck.msg);
        const wfCheck = window.checkWorkforceAvailability(window.stCurrentTier, window.stCurrentWorkers);
        if (!wfCheck.ok) return alert(wfCheck.msg);
        if (wfCheck.needConfirm && !confirm(wfCheck.msg)) return;

        let rawName = $('#build-input-name').val();
        if (!rawName || rawName.trim() === '') return alert("❌ Vui lòng nhập Tên công trình!");
        const type = $('#build-select-type').val();
        const size = parseInt($('#build-input-size').val()) || 1; 
        let finalName = rawName.trim(), extraVar = '', extraInstruction = '';

        if (type === 'Quân sự') {
            const milType = $('#build-military-type').val();
            if (milType === 'Đơn vị đặc chủng') {
                const selectedHero = $('#build-military-hero').val();
                const heroClass = $('#build-military-hero option:selected').attr('data-class');
                if (!selectedHero) return alert("❌ Không có Anh hùng! Không thể lập Đơn vị đặc chủng.");
                finalName = `Trại đặc chủng ${rawName}`;
                extraVar = `, ${window.k('Huấn-luyện')}: "Đặc chủng"`;

                // Lệnh tạo Đơn vị đặc chủng dạng Array
                extraInstruction = `\n\n[KHỞI TẠO ĐẶC CHỦNG]: Quan Chấp Hành BẮT BUỘC thêm 1 Object mới vào MẢNG [Quân_sự.Chi_tiết_binh_chủng.Đơn_vị_đặc_chủng] với cấu trúc: { Tên_đơn_vị: "${rawName}", Số_lượng: 0, Lãnh_đạo: "${selectedHero}", Đặc_chủng: "${heroClass}" }.`;
            } else {
                finalName = `Trại ${milType.toLowerCase()} ${rawName}`;
                extraVar = `, ${window.k('Huấn-luyện')}: "${milType}"`;
            }
        }

        // Sửa Prompt xây dựng: Thêm vào MẢNG Đang_xây_dựng thay vì tạo Key
        let msg = `Ta quy hoạch ô đất trống tại tọa độ [${window.stCurrentSelectedCoord}] để khởi công xây dựng [${finalName}] (Thuộc nhóm: ${type}).\n\nYÊU CẦU QUAN CHẤP HÀNH THỰC HIỆN ĐỒNG BỘ:\n1. TRỪ vật liệu và ngân khố: [${window.stCurrentCostString}].\n2. TẠO HỒ SƠ THI CÔNG: Hãy thêm (push) 1 Object mới vào MẢNG dữ liệu [Bản_đồ.Đang_xây_dựng].\n3. ĐIỀN THÔNG SỐ VÀO OBJECT ĐÓ NHƯ SAU: Tên_kiến_trúc: "${finalName}", Tọa_độ: "${window.stCurrentSelectedCoord}", Kích_thước: ${size}, Nhân_công: "${window.stCurrentWorkers} ${window.stCurrentTier}", Thời_gian_còn_lại: "${window.stCurrentDays} ngày", Tiến_độ: "0%"${extraVar}.`;

        if (size > 1) {
            msg += `\n4. [LUẬT ĐIỂM NEO KHÔNG GIAN]: Vì đây là đại công trình quy mô ${size}x${size}, yêu cầu khóa chặt khu vực ${size}x${size} ô vuông xung quanh tọa độ gốc, tuyệt đối không cho phép xâm lấn.`;
        }
        msg += extraInstruction;

        if (wfCheck.needConfirm) msg += `\n[LỆNH CƯỠNG CHẾ]: Rút ${wfCheck.pullAmount} người từ nhóm "${wfCheck.pullCategory}" đi làm phu xây dựng.`;

        window.sendCommandToAI(msg); $('#map-build-panel').fadeOut();
    };

    window.updatePathBuildCost = function() {
        const name = $('#build-path-name').val();
        const type = $('#build-path-type').val();
        const days = $('#build-path-days').val();
        const tier = $('#build-path-tier').val();

        if (name) {
            const L = window.stCurrentPathLength; 
            let baseCost = type === 'Tường thành' ? { wood: 50, stone: 200, iron: 10, food: 30, adminGold: 20 } : { wood: 20, stone: 50, iron: 0, food: 10, adminGold: 5 };
            const totalMat = { wood: baseCost.wood * L, stone: baseCost.stone * L, iron: baseCost.iron * L, food: baseCost.food * L };
            const actualAdminGold = baseCost.adminGold * L; 
            const totalWorkload = totalMat.wood + (totalMat.stone * 2) + (totalMat.iron * 4);
            const tierInfo = window.workerTiers[tier] || window.workerTiers['Lành nghề'];
            const actualDays = Math.max(1, parseInt(days) || 7);
            const reqWorkers = Math.max(1, Math.ceil(totalWorkload / (tierInfo.capacity * actualDays)));
            const totalLaborCost = Math.ceil(reqWorkers * tierInfo.dailyWage * actualDays);
            const finalGold = totalLaborCost + actualAdminGold;

            const data = { costObj: { gold: finalGold, wood: totalMat.wood, stone: totalMat.stone, iron: totalMat.iron, food: totalMat.food }, workers: reqWorkers, days: actualDays, tierName: tier };
            data.html = `<div style="margin-bottom: 4px;">💰 <b>Vàng: ${finalGold}</b> <span style="font-size:0.7em; color:#8B6914;">(Lương: ${totalLaborCost} + Phí quy hoạch: ${actualAdminGold})</span></div><div style="margin-bottom: 4px; font-size: 0.9em;">🌳 Gỗ: ${totalMat.wood} | ⛰ Đá: ${totalMat.stone} | ⛏️ Sắt: ${totalMat.iron}</div><div style="color: #2D5016; border-top: 1px dashed #C9A227; padding-top: 4px; margin-top: 4px; font-size: 0.95em;">👷 Yêu cầu: <b>${reqWorkers} ${tier}</b></div>`;
            saveCostData(data); $('#build-path-cost-val').html(data.html);
        } else {
            window.stCurrentCostRaw = null; $('#build-path-cost-val').html("Vui lòng nhập tên...");
        }
    };

    window.stExecutePathBuild = function() {
        if (!window.stCurrentCostRaw) return;
        const resCheck = window.checkResources(window.stCurrentCostRaw);
        if (!resCheck.ok) return alert(resCheck.msg);
        const wfCheck = window.checkWorkforceAvailability(window.stCurrentTier, window.stCurrentWorkers);
        if (!wfCheck.ok) return alert(wfCheck.msg);
        if (wfCheck.needConfirm && !confirm(wfCheck.msg)) return;

        const name = $('#build-path-name').val() || 'Tuyến mới';
        const type = $('#build-path-type').val();
        const targetVar = type === 'Tường thành' ? 'Tường-thành' : 'Đường-đi';
        const length = window.stCurrentPathLength;

        // Sửa Prompt xây hạ tầng: Thêm vào mảng Đang_xây_dựng, và lưu ý ghi chú mảng đích
