        if (wfCheck.needConfirm) msg += `\n\n[CƯỠNG CHẾ ĐIỀU ĐỘNG]: Rút ${wfCheck.pullAmount} người từ các công trình "${wfCheck.pullCategory}" để phục vụ tuyến này.`;

