    window.jumpToCoord = function(coordStr) {
        if (!coordStr || typeof coordStr !== 'string') coordStr = $('#jump-coord-input').val();
        if (!coordStr) return;
        const parts = coordStr.split(',');
        if (parts.length !== 2) return;
        const x = Number(parts[0]), y = Number(parts[1]);
        if (!isNaN(x) && !isNaN(y)) {
            window.currentCenterX = x; window.currentCenterY = y;
            const scroller = $('#map-scroll');
            if (scroller.length === 0) return;
            scroller.animate({ scrollLeft: (x * gridSize) + (gridSize / 2) - (scroller.width() / 2), scrollTop: (y * gridSize) + (gridSize / 2) - (scroller.height() / 2) }, 300);
            $('.map-highlight-ping').remove(); 
            const ping = $('<div class="map-highlight-ping" style="position:absolute; width:50px; height:50px; border:3px solid #ff4d4d; border-radius:8px; box-shadow: 0 0 20px #ff4d4d, inset 0 0 10px #ff4d4d; z-index:999; pointer-events:none; background: rgba(255,77,77,0.3);"></div>');
            ping.css({ left: (x * gridSize) + 'px', top: (y * gridSize) + 'px' });
            $('#map-world-canvas').append(ping);
            ping.fadeOut(3000, function(){ $(this).remove() });
        }
    };

    window.mapReset = function() { window.jumpToCoord(window.currentCenterX + ',' + window.currentCenterY); };
    window.toggleFullscreenMap = function() {
        const mapContainer = document.getElementById('pane-map');
        if (!document.fullscreenElement) {
            if (mapContainer.requestFullscreen) mapContainer.requestFullscreen();
            else if (mapContainer.webkitRequestFullscreen) mapContainer.webkitRequestFullscreen();
        } else {
            if (document.exitFullscreen) document.exitFullscreen();
        }
    };

