    window.showMapInfo = function(info, coord) {
        window.stCurrentSelectedCoord = coord; window.stCurrentSelectedName = info.name;
        $('#info-icon').text(info.icon); $('#info-name').text(info.name || 'Chưa rõ');
        $('#info-coord').text(coord || '???'); $('#info-type').text(info.type || 'Không xác định');
        $('#info-capacity-curr').text(info.capCurr || 0);
        $('#info-capacity-max').text(info.capMax || 0);
        $('#info-production').text(info.production || 'Không có');
        if ((info.capCurr || 0) > (info.capMax || 0)) $('#info-capacity-curr').css('color', '#8B2323');
        else $('#info-capacity-curr').css('color', '#2C1810');

        $('#row-military, #row-economy').hide();
        $('#info-action-buttons, #info-capital-actions, #info-explore-actions, #info-construction-actions, #info-resource-actions, #info-infra-actions').hide();
        $('#upgrade-cost-container, #construction-info-container').hide();

        if (info.isUnderConstruction) {
            $('#row-level, #row-status, #row-capacity-workers, #row-production').hide(); 
            $('#info-build-progress').text(info.progress);
            $('#info-build-time').text(info.timeLeft);
            $('#info-build-workers').text(info.workers); 
            $('#construction-info-container').show();
            $('#info-construction-actions').css('display', 'flex');
        } else {
            $('#row-level, #row-status').show();
            $('#info-level').text(info.level || 'N/A');
            $('#info-status').text(info.status || 'N/A');

            if (info.isPlayerOwned) {
                $('#row-capacity-workers, #row-production').show();
                $('#info-action-buttons').css('display', 'flex');
                window.updateUpgCost(); 
                $('#upgrade-cost-container').show();
            } else if (info.isCapital) {
                $('#row-capacity-workers, #row-production').hide();
                $('#row-military').show(); $('#info-military').text(info.military || 'Chưa rõ');
                $('#row-economy').show(); $('#info-economy').text(info.economy || 'Chưa rõ');
                $('#info-capital-actions').css('display', 'flex');
            } else if (info.isInfrastructure) {
                $('#row-capacity-workers, #row-production').hide();
                if (info.isForeign) $('#info-explore-actions').css('display', 'flex');
                else $('#info-infra-actions').css('display', 'flex');
            } else if (info.isOutsideArea) {
                $('#row-capacity-workers, #row-production').hide();
                $('#info-resource-actions').css('display', 'flex');
                if (info.hasDanger) { $('#btn-subjugate').show(); $('#btn-manual-harvest').hide(); } 
                else { $('#btn-subjugate').hide(); $('#btn-manual-harvest').show(); }
            } else {
                $('#row-capacity-workers, #row-production').hide();
                $('#info-explore-actions').css('display', 'flex');
                if (info.isCommercial) $('#btn-trade').show();
            }
        }
