    window.stRepairBuilding = function() { 
        const name = window.stCurrentSelectedName;
        const coord = window.stCurrentSelectedCoord;
        const type = $('#info-type').text();
        const level = $('#info-level').text() || '1';

        let origCost = { gold: 0, wood: 0, stone: 0, iron: 0, food: 0 };

        function getCoordLength(rangeStr) {
            if (!rangeStr || !rangeStr.includes('-')) return 1;
            const parts = rangeStr.split('-');
            const p1 = parts[0].trim().split(',').map(Number);
            const p2 = parts[1].trim().split(',').map(Number);
            return Math.max(Math.abs(p1[0] - p2[0]), Math.abs(p1[1] - p2[1])) + 1;
        }

        if (type === 'Phòng thủ' && name.toLowerCase().includes('tường')) {
            const L = getCoordLength(coord);
            origCost = { wood: 50 * L, stone: 200 * L, iron: 10 * L, food: 30 * L, gold: 50 * L }; 
        } else if (type === 'Giao thông') {
            const L = getCoordLength(coord);
            origCost = { wood: 20 * L, stone: 50 * L, iron: 0, food: 10 * L, gold: 20 * L };
        } else {
            const calc = window.calculateEconomics(name, type, false, level, 7, 'Lành nghề', 1);
            origCost = calc.costObj;
        }

        const repairCost = {
            gold: Math.ceil(origCost.gold * 0.1), wood: Math.ceil(origCost.wood * 0.1), stone: Math.ceil(origCost.stone * 0.1),
            iron: Math.ceil(origCost.iron * 0.1), food: Math.ceil(origCost.food * 0.1)
        };

        let costArr = [];
        if (repairCost.gold > 0) costArr.push(repairCost.gold + ' Vàng');
        if (repairCost.wood > 0) costArr.push(repairCost.wood + ' Gỗ');
        if (repairCost.stone > 0) costArr.push(repairCost.stone + ' Đá');
        if (repairCost.iron > 0) costArr.push(repairCost.iron + ' Sắt');

        const costStr = costArr.join(', ');

        if(confirm(`Tiến hành tu sửa và bảo trì [${name}]?\n\n💰 Chi phí khấu hao (10% giá gốc):\n👉 ${costStr}`)) { 
            const resCheck = window.checkResources(repairCost);
            if (!resCheck.ok) return alert("❌ QUỸ BẢO TRÌ THIẾU HỤT!\n" + resCheck.msg);

            let msg = `Lệnh xuất ngân khố và vật tư để sửa chữa, bảo trì [${name}] tại [${coord}]. BẮT BUỘC THỰC HIỆN CÁC BƯỚC SAU:\n1. Trừ đi chi phí vật liệu bảo trì: [${costStr}] ra khỏi [Vật_tư_kho] và [Vàng_tồn_kho].\n2. Cập nhật lại Trạng_thái của công trình này về mức "Nguyên vẹn 100%" hoặc "Hoạt động tốt".`; 
            window.sendCommandToAI(msg); 
            $('#map-info-panel').fadeOut(); 
        } 
    };

    // --- RENDERING BẢN ĐỒ LỚN CỐT LÕI ---
window.renderMapData = function(mapData) {
        const canvas = document.getElementById('map-world-canvas');
        if (!canvas) return; 
        canvas.innerHTML = ''; 
        document.getElementById('map-info-panel').style.display = 'none';
        if (!mapData || typeof mapData !== 'object') return;

        // Đã sửa Vùng đã khám phá thành Array theo schema mới
        let exploredList = window.safeGet(mapData, 'Vùng-đã-khám-phá', []);
        if (!Array.isArray(exploredList)) exploredList = [];

        const expandedExploredSet = new Set();
        window.stExploredSet = expandedExploredSet; 
        const visionRadius = 2; 
        if (exploredList.length === 0) exploredList.push("500,500");

        exploredList.forEach(centerCoord => {
            const parts = String(centerCoord).split(',');
            if (parts.length !== 2) return;
            const cx = parseInt(parts[0]); const cy = parseInt(parts[1]);
            if (!isNaN(cx) && !isNaN(cy)) {
                for (let dx = -visionRadius; dx <= visionRadius; dx++) {
                    for (let dy = -visionRadius; dy <= visionRadius; dy++) {
                        expandedExploredSet.add((cx + dx) + ',' + (cy + dy));
                    }
                }
            }
        });

        let svgHTML = `<svg id="world-svg-layers" width="50000" height="50000" style="position:absolute; top:0; left:0; pointer-events:none; z-index:0;">`;
        svgHTML += `<defs><mask id="fog-mask"><rect width="50000" height="50000" fill="black" />`;

        expandedExploredSet.forEach(coordStr => {
            let parts = coordStr.split(',');
            svgHTML += `<rect x="${parseInt(parts[0]) * gridSize}" y="${parseInt(parts[1]) * gridSize}" width="${gridSize}" height="${gridSize}" fill="white" />`;
        });
        svgHTML += `</mask></defs>`;

        svgHTML += `<g mask="url(#fog-mask)">`;
        svgHTML += `<rect width="50000" height="50000" fill="#87CEEB" />`; 

        mapBorderData.territoriesData.forEach(t => {
            let pts = t.points.map(p => `${p[0] * gridSize},${p[1] * gridSize}`).join(' ');
            if (t.isLandmass) {
                svgHTML += `<polygon points="${pts}" fill="#E8D4A8" stroke="${t.border}" stroke-width="4" />`;
            } else {
                svgHTML += `<polygon points="${pts}" fill="none" stroke="${t.border}" stroke-width="3" stroke-linejoin="round" />`;
            }
        });

        svgHTML += `</g></svg>`;
        canvas.innerHTML = svgHTML;

        expandedExploredSet.forEach(coordStr => {
            const parts = coordStr.split(',');
            const x = parseInt(parts[0]); const y = parseInt(parts[1]);
            const tile = document.createElement('div');
            tile.className = 'map-explored-tile';
            tile.style.left = (x * gridSize) + 'px';
            tile.style.top = (y * gridSize) + 'px';
            canvas.appendChild(tile);

            if (x % 2 === 0 && y % 2 === 0) {
                const label = document.createElement('div');
                label.className = 'axis-label';
                label.style.left = (x * gridSize) + 'px';
                label.style.top = (y * gridSize) + 'px';
                label.textContent = x + ',' + y;
                canvas.appendChild(label);
            }
        });

        const drawItem = (coordStr, htmlContent, infoData, size = 1) => {
            if (!expandedExploredSet.has(coordStr)) return;
            const parts = String(coordStr).split(',');
            if (parts.length !== 2) return;
            const x = parseInt(parts[0]); const y = parseInt(parts[1]);

            if (!isNaN(x) && !isNaN(y)) {
                const el = document.createElement('div');
                el.className = 'map-item';

                const offset = -Math.floor((size - 1) / 2) * gridSize;
                const renderSize = size * gridSize;

                el.style.left = (x * gridSize) + 'px'; 
                el.style.top = (y * gridSize) + 'px';
                el.style.width = renderSize + 'px'; 
                el.style.height = renderSize + 'px';

                el.style.marginLeft = offset + 'px';
                el.style.marginTop = offset + 'px';
                if (size > 1) el.style.zIndex = 15; 

                el.innerHTML = htmlContent;

                const iconDiv = el.querySelector('.map-building');
                if (iconDiv && size > 1) {
                    iconDiv.style.fontSize = (size * 0.8) + 'rem';
                    iconDiv.style.borderRadius = '8px'; 
                    iconDiv.style.borderWidth = '2px';
                    iconDiv.style.boxShadow = '3px 3px 10px rgba(0,0,0,0.5)';
                }

                el.onclick = function(e) {
                    e.stopPropagation(); 
                    if (infoData.isEmptyZone) window.showBuildPanel(coordStr);
                    else window.showMapInfo(infoData, coordStr);
                };
                canvas.appendChild(el);
            }
        };

        function getCoordsFromRange(rangeStr) {
            let coords = []; const parts = String(rangeStr).split('-');
            const p1 = parts[0].trim().split(',').map(Number);
            const p2 = (parts.length === 2 ? parts[1].trim() : parts[0].trim()).split(',').map(Number);
            if(p1.length === 2 && p2.length === 2 && !isNaN(p1[0]) && !isNaN(p2[0])) {
                const minX = Math.min(p1[0], p2[0]), maxX = Math.max(p1[0], p2[0]);
                const minY = Math.min(p1[1], p2[1]), maxY = Math.max(p1[1], p2[1]);
                for (let x = minX; x <= maxX; x++) { for (let y = minY; y <= maxY; y++) coords.push(x + ',' + y); }
            }
            return coords;
        }

        const roadCells = new Map();
        const wallCells = new Map();

        // SỬA: Đường đi (Array)
        const roadArr = window.safeGet(mapData, 'Đường-đi', []);
        if (Array.isArray(roadArr)) {
            roadArr.forEach(rData => {
                const name = window.safeGet(rData, 'Tên-đường', 'Đường vô danh');
                const r = window.safeGet(rData, 'Tọa-độ', '');
                if (r) getCoordsFromRange(r).forEach(c => roadCells.set(c, {name: name, rangeStr: r, isForeign: false}));
            });
        }

        // SỬA: Tường thành (Array)
        const wallArr = window.safeGet(mapData, 'Tường-thành', []);
        if (Array.isArray(wallArr)) {
            wallArr.forEach(wData => {
                const name = window.safeGet(wData, 'Tên-đoạn-tường', 'Tường vô danh');
                const r = window.safeGet(wData, 'Tọa-độ', '');
                if (r) getCoordsFromRange(r).forEach(c => wallCells.set(c, {name: name, rangeStr: r, isForeign: false}));
            });
        }

        // SỬA: Thế giới Mở rộng (Array)
        const extWorldArr = window.safeGet(mapData, 'Thế-giới-Mở-rộng', []);
        if (Array.isArray(extWorldArr)) {
            extWorldArr.forEach(data => {
                const name = window.safeGet(data, 'Tên-thế-lực', 'Thế lực vô danh');
                const centerCoord = window.safeGet(data, 'Tọa-độ-Trung-tâm');
                const kingdomStatus = window.safeGet(data, 'Trạng-thái', 'Hoạt động');
                const kingdomDesc = window.safeGet(data, 'Giới-thiệu', 'Cơ quan đầu não.');
                const kingdomMil = window.safeGet(data, 'Chi-tiến-lực', 'Bí ẩn'); // Theo schema của ngài là Chi_tiến_lực
                const kingdomEco = window.safeGet(data, 'Kinh-tế', 'Bí ẩn');

                const ktnb = window.safeGet(data, 'Kiến-trúc-Nổi-bật', {});
                let hasCapitalBuilding = false; 

                // Công trình nội bộ thế lực (Array)
                const kbBuildings = window.safeGet(ktnb, 'Công-trình', []);
                if (Array.isArray(kbBuildings)) {
                    kbBuildings.forEach(bData => {
                        const bName = window.safeGet(bData, 'Tên-công-trình', 'Công trình');
                        const bType = window.safeGet(bData, 'Loại', '');
                        const bInfo = window.getBuildingInfo(bName, bType);
                        const bCoord = window.safeGet(bData, 'Tọa-độ');
                        const bSize = Number(window.safeGet(bData, 'Kích-thước', 1));

                        if (bCoord === centerCoord || bInfo.category === 'hành chính') {
                            hasCapitalBuilding = true;
                            const html = `<div class="map-building" style="border-color:#2C1810; background: linear-gradient(135deg, #E8D4A8 0%, #8B6914 100%);">${bInfo.icon}</div>`;
                            drawItem(bCoord, html, {
                                icon: bInfo.icon, name: `${bName} (${name})`, type: 'Thủ phủ Ngoại bang', level: 'Trung tâm', status: kingdomStatus, 
                                desc: kingdomDesc, isCapital: true, military: kingdomMil, economy: kingdomEco 
                            }, bSize); 
                        } else {
                            const html = `<div class="map-building ${bInfo.class}">${bInfo.icon}</div>`;
                            drawItem(bCoord, html, { 
                                icon: bInfo.icon, name: bName, type: bType, desc: 'Thuộc lãnh thổ: ' + name, 
                                isCapital: false, isPlayerOwned: false, isCommercial: (bInfo.category === 'thương mại' || bInfo.category === 'sản xuất') 
                            }, bSize);
                        }
                    });
                }

                if (centerCoord && !hasCapitalBuilding) {
                    const html = '<div class="map-building" style="border-color:#8B6914; border-radius:50%; background: #4A3728; color:#F5E6C8; font-weight:bold;">❓</div>';
                    drawItem(centerCoord, html, {
                        icon: '❓', name: name, type: 'Chưa khám phá', level: 'Bí ẩn', status: kingdomStatus, desc: kingdomDesc,
                        isCapital: true, military: kingdomMil, economy: kingdomEco
                    }, 1); 
                }

                // Tường và Đường nội bộ thế lực (Array)
                const kbWalls = window.safeGet(ktnb, 'Tường-thành', []);
                if (Array.isArray(kbWalls)) {
                    kbWalls.forEach(wData => {
                        const wName = window.safeGet(wData, 'Tên-đoạn-tường', '');
                        const r = window.safeGet(wData, 'Tọa-độ', '');
                        if(r) getCoordsFromRange(r).forEach(c => wallCells.set(c, {name: `${wName} (${name})`, rangeStr: r, isForeign: true}));
                    });
                }

                const kbRoads = window.safeGet(ktnb, 'Đường-đi', []);
                if (Array.isArray(kbRoads)) {
                    kbRoads.forEach(rData => {
                        const rName = window.safeGet(rData, 'Tên-đường', '');
                        const r = window.safeGet(rData, 'Tọa-độ', '');
                        if(r) getCoordsFromRange(r).forEach(c => roadCells.set(c, {name: `${rName} (${name})`, rangeStr: r, isForeign: true}));
                    });
                }
            });
        }

        // SỬA: Công trình chính (Category Object chứa các Array)
        if (window.safeGet(mapData, 'Công-trình')) {
            const allBuildings = window.safeGet(mapData, 'Công-trình');
            Object.entries(allBuildings).forEach(([categoryStr, categoryArray]) => {
                if (!Array.isArray(categoryArray)) return;
                const categoryName = categoryStr.replace(/\x5F/g, ' ').replace(/_/g, ' '); 

                categoryArray.forEach(bData => {
                    let bName = window.safeGet(bData, 'Tên-công-trình');
                    if (!bName) bName = window.safeGet(bData, 'Tên-khu-dân-cư', 'Công trình vô danh');

                    const bInfo = window.getBuildingInfo(bName, categoryName); 
                    const html = `<div class="map-building ${bInfo.class}">${bInfo.icon}</div>`;
                    const bSize = Number(window.safeGet(bData, 'Kích-thước', 1));

                    let capCurr = 0, capMax = 0;
                    if (window.safeGet(bData, 'Nhân-khẩu')) { capCurr = window.safeGet(bData, 'Nhân-khẩu.Hiện-tại', 0); capMax = window.safeGet(bData, 'Nhân-khẩu.Tối-đa', 0); }
                    else if (window.safeGet(bData, 'Nhân-lực')) { capCurr = window.safeGet(bData, 'Nhân-lực.Hiện-tại', 0); capMax = window.safeGet(bData, 'Nhân-lực.Tối-đa', 0); }
                    else if (window.safeGet(bData, 'Binh-lính')) { capCurr = window.safeGet(bData, 'Binh-lính.Hiện-tại', 0); capMax = window.safeGet(bData, 'Binh-lính.Tối-đa', 0); }
                    else if (window.safeGet(bData, 'Số-lượng-hàng-hóa')) { capCurr = window.safeGet(bData, 'Số-lượng-hàng-hóa.Hiện-tại', 0); capMax = window.safeGet(bData, 'Số-lượng-hàng-hóa.Tối-đa', 0); }

                    let details = [];
                    const ignoreKeys = ['Tọa_độ', 'Cấp_độ', 'Trạng_thái', 'Kích_thước', 'Nhân_khẩu', 'Nhân_lực', 'Binh_lính', 'Số_lượng_hàng_hóa', 'Tên_công_trình', 'Tên_khu_dân_cư'];

                    Object.entries(bData).forEach(([k, v]) => {
                        const checkKey = k.replace(/-/g, '_'); 
                        if (!ignoreKeys.includes(checkKey) && typeof v !== 'object' && v !== undefined) {
                            const formattedKey = k.replace(/\x5F/g, ' ').replace(/-/g, ' ');
                            details.push(formattedKey.charAt(0).toUpperCase() + formattedKey.slice(1) + ": " + v);
                        }
                    });

                    drawItem(window.safeGet(bData, 'Tọa-độ'), html, { 
                        icon: bInfo.icon, name: bName, type: categoryName, level: window.safeGet(bData, 'Cấp-độ', 1), status: window.safeGet(bData, 'Trạng-thái', 'Bình thường'), 
                        capCurr: capCurr, capMax: capMax, production: details.length > 0 ? details.join(" | ") : "Không có", isPlayerOwned: true, isCapital: categoryName.toLowerCase() === 'hành chính' 
                    }, bSize);
                });
            });
        }

        // SỬA: Đang xây dựng (Array)
        const ucArray = window.safeGet(mapData, 'Đang-xây-dựng', []);
        if (Array.isArray(ucArray)) {
            ucArray.forEach(data => {
                const name = window.safeGet(data, 'Tên-kiến-trúc', 'Đang thi công');
                const bSize = Number(window.safeGet(data, 'Kích-thước', 1));
                const html = '<div class="map-building" style="background: rgba(255, 153, 0, 0.2); border: 2px dashed #FF9900; animation: pulse 2s infinite;">🚧</div>';
                drawItem(window.safeGet(data, 'Tọa-độ'), html, { 
                    icon: '🚧', name: name, type: 'Đang thi công', isUnderConstruction: true,
                    progress: window.safeGet(data, 'Tiến-độ', '0%'), timeLeft: window.safeGet(data, 'Thời-gian-còn-lại', 'Chưa rõ'), workers: window.safeGet(data, 'Nhân-công', 'Đang trống') 
                }, bSize);
            });
        }

        const roadLayer = document.createElement('div'); roadLayer.className = 'road-layer'; canvas.appendChild(roadLayer);
        const wallLayer = document.createElement('div'); wallLayer.className = 'wall-layer'; canvas.appendChild(wallLayer);
        const nodeLayer = document.createElement('div'); nodeLayer.className = 'node-layer'; canvas.appendChild(nodeLayer);

        roadCells.forEach((data, coordStr) => {
            const parts = coordStr.split(','); const x = Number(parts[0]); const y = Number(parts[1]);
            const t = roadCells.has(x + ',' + (y-1)), b = roadCells.has(x + ',' + (y+1)), l = roadCells.has((x-1) + ',' + y), r = roadCells.has((x+1) + ',' + y);
            const cell = document.createElement('div'); cell.className = 'interactive-cell';
            cell.style.left = (x * gridSize) + 'px'; cell.style.top = (y * gridSize) + 'px'; cell.style.width = gridSize + 'px'; cell.style.height = gridSize + 'px';
            cell.onclick = (e) => { e.stopPropagation(); window.showMapInfo({ icon: '🛣️', name: data.name, type: 'Giao thông', isInfrastructure: true, isForeign: data.isForeign }, data.rangeStr); };
            let html = '<div class="map-road" style="left:10px; top:10px; width:10px; height:10px; ' + ((!t&&!b&&!l&&!r) ? 'border-radius:50%;' : '') + '"></div>';
            if (t) html += '<div class="map-road" style="left:10px; top:0px; width:10px; height:10px;"></div>';
            if (b) html += '<div class="map-road" style="left:10px; top:20px; width:10px; height:10px;"></div>';
            if (l) html += '<div class="map-road" style="left:0px; top:10px; width:10px; height:10px;"></div>';
            if (r) html += '<div class="map-road" style="left:20px; top:10px; width:10px; height:10px;"></div>';
            cell.innerHTML = html; roadLayer.appendChild(cell);
        });

        wallCells.forEach((data, coordStr) => {
            const parts = coordStr.split(','); const x = Number(parts[0]); const y = Number(parts[1]);
            const t = wallCells.has(x + ',' + (y-1)), b = wallCells.has(x + ',' + (y+1)), l = wallCells.has((x-1) + ',' + y), r = wallCells.has((x+1) + ',' + y);
            const cell = document.createElement('div'); cell.className = 'interactive-cell';
            cell.style.left = (x * gridSize) + 'px'; cell.style.top = (y * gridSize) + 'px'; cell.style.width = gridSize + 'px'; cell.style.height = gridSize + 'px';
            cell.onclick = (e) => { e.stopPropagation(); window.showMapInfo({ icon: '🧱', name: data.name, type: 'Phòng thủ', isInfrastructure: true, isForeign: data.isForeign }, data.rangeStr); };

            let html = '<div class="map-wall" style="left:5px; top:5px; width:20px; height:20px;"></div>';
            if (t) html += '<div class="map-wall" style="left:5px; top:0px; width:20px; height:5px;"></div>';
            if (b) html += '<div class="map-wall" style="left:5px; top:25px; width:20px; height:5px;"></div>';
            if (l) html += '<div class="map-wall" style="left:0px; top:5px; width:5px; height:20px;"></div>';
            if (r) html += '<div class="map-wall" style="left:25px; top:5px; width:5px; height:20px;"></div>';
            cell.innerHTML = html; wallLayer.appendChild(cell);

            if (!(l && r && !t && !b) && !(t && b && !l && !r)) {
                const node = document.createElement('div'); node.className = 'map-wall-node';
                node.style.left = (x * gridSize + 3) + 'px'; node.style.top = (y * gridSize + 3) + 'px'; node.style.width = '24px'; node.style.height = '24px';
                nodeLayer.appendChild(node);
            }
        });

        // SỬA: Cổng thành (Array)
        const gateArr = window.safeGet(mapData, 'Cổng-thành', []);
        if (Array.isArray(gateArr)) {
            gateArr.forEach(data => {
                const name = window.safeGet(data, 'Tên-cổng', 'Cổng vô danh');
                const parts = String(window.safeGet(data, 'Tọa-độ')).split(',');
                const x = Number(parts[0]); const y = Number(parts[1]);
                if (!isNaN(x) && !isNaN(y)) {
                    const el = document.createElement('div'); el.className = 'map-gate';
                    el.style.left = (x * gridSize) + 'px'; el.style.top = (y * gridSize) + 'px'; el.style.width = gridSize + 'px'; el.style.height = gridSize + 'px';
                    el.innerHTML = '🚪';
                    el.onclick = (e) => { e.stopPropagation(); window.showMapInfo({ icon: '🚪', name: name, type: 'Cổng thành', status: 'Hướng: ' + window.safeGet(data, 'Hướng'), isInfrastructure: true, isForeign: false }, window.safeGet(data, 'Tọa-độ')); };
                    canvas.appendChild(el);
                }
            });
        }

        // SỬA: Khu vực ngoài lãnh thổ (Array)
        const outsideArr = window.safeGet(mapData, 'Khu-vực-ngoài-lãnh-thổ', []);
        if (Array.isArray(outsideArr)) {
            const allVars = window.getMVUVars();
            const resData = window.safeGet(allVars, 'stat-data.Lãnh-địa.Tài-nguyên', {});

            outsideArr.forEach(data => {
                const name = window.safeGet(data, 'Tên-khu-vực', 'Chưa rõ');
                const typeStr = String(window.safeGet(data, 'Loại', '')).toLowerCase();
                const statusStr = String(window.safeGet(data, 'Trạng-thái', '')).toLowerCase();
                const nameStr = String(name).toLowerCase();
                const bSize = Number(window.safeGet(data, 'Kích-thước', 1));

                // Thuật toán quét mối đe dọa ẩn xuyên qua Mảng Tài nguyên
                let hiddenThreat = '';
                for (let cat of ['Rừng-rậm', 'Mạch-khoáng', 'Nguồn-nước']) {
                    const resArr = window.safeGet(resData, cat, []);
                    if (Array.isArray(resArr)) {
                        const foundRes = resArr.find(item => String(window.safeGet(item, 'Tên-khu-vực')).toLowerCase() === nameStr);
                        if (foundRes) {
                            const threat = String(window.safeGet(foundRes, 'Mối-đe-dọa', '')).trim();
                            if (threat && !['không có', 'an toàn', 'không'].includes(threat.toLowerCase())) { hiddenThreat = threat; }
                            break;
                        }
                    }
                }

                const isBaseDanger = typeStr.includes('quái vật') || typeStr.includes('cướp') || typeStr.includes('địch') || typeStr.includes('tặc') || nameStr.includes('cướp') || nameStr.includes('quái vật') || nameStr.includes('tặc') || statusStr.includes('nguy hiểm');
                const isSafeStatus = statusStr.includes('an toàn') || statusStr.includes('dọn dẹp') || statusStr.includes('đã khai phá') || statusStr.includes('sẵn sàng khai thác');
                const isDanger = isSafeStatus ? false : (isBaseDanger || hiddenThreat !== '');

                const cssClass = isDanger ? 'map-monster' : 'map-resource';
                let icon = '⛰️'; 
                if (isBaseDanger) { icon = (typeStr.includes('cướp') || typeStr.includes('tặc') || nameStr.includes('cướp') || nameStr.includes('tặc')) ? '☠️' : '👹'; } 
                else {
                    if (typeStr.includes('rừng') || nameStr.includes('rừng')) icon = '🌲';
                    else if (typeStr.includes('nước') || typeStr.includes('suối') || typeStr.includes('hồ') || nameStr.includes('suối') || nameStr.includes('hồ')) icon = '💧';
                    else if (typeStr.includes('di tích') || nameStr.includes('di tích') || typeStr.includes('phế tích')) icon = '🏛️';
                }

                let displayIcon = icon;
                if (!isBaseDanger && hiddenThreat !== '') { displayIcon = '<div style="position:relative; display:flex; align-items:center; justify-content:center;">' + icon + '<span style="position:absolute; top:-8px; right:-8px; font-size:12px; text-shadow:1px 1px 2px #000;">⚠️</span></div>'; }

                let descText = 'Nguồn Tài nguyên';
                if (isBaseDanger) descText = '⚠️ Khu vực Nguy hiểm!';
                else if (hiddenThreat !== '') descText = '⚠️ Đang bị chiếm đóng bởi: <b style="color:#8B2323">' + hiddenThreat + '</b>';

                const html = `<div class="map-building ${cssClass}">${displayIcon}</div>`;
                drawItem(window.safeGet(data, 'Tọa-độ'), html, { 
                    icon: icon, name: name, type: window.safeGet(data, 'Loại'), level: 'Ngoại cảnh', status: window.safeGet(data, 'Trạng-thái'), 
                    desc: descText, isOutsideArea: true, hasDanger: isDanger 
                }, bSize);
            });
        }
    };

    /* ==========================================================================
       PHẦN 8: MODULE PHÁP LỆNH (Quản lý Chính sách & Gửi dự thảo cho AI)
       ========================================================================== */

    // Bộ nhớ đệm (Buffer) để lưu tạm các thay đổi trước khi chính thức ban hành
    window.stDecreeBuffer = { new: [], modified: [], abolished: [] };

    // --- Render danh sách đạo luật hiện tại ---
    window.renderDecreeModule = function(decreeData) {
        if (!decreeData || typeof decreeData !== 'object') return;

        $('#decree-status-general').text(window.safeGet(decreeData, 'Trạng-thái-thi-hành-chung', 'Chưa khởi tạo'));
        $('#decree-overview').text(window.safeGet(decreeData, 'Tổng-quan-hiện-tại', 'Chưa có pháp lệnh nào được ban hành.'));

        const dContainer = $('#decree-list-container');
        dContainer.empty();

        // SỬA: Danh-sách-chi-tiết hiện tại là Mảng, default là []
        const dList = window.safeGet(decreeData, 'Danh-sách-chi-tiết', []);

        // Kiểm tra xem mảng có trống không
        if (!Array.isArray(dList) || dList.length === 0) {
            dContainer.append('<div class="decree-empty">Chưa có đạo luật nào trong hệ thống.</div>');
        } else {
            dList.forEach(d => {
                // SỬA: Rút tên pháp lệnh từ bên trong object thay vì từ Key
                const name = window.safeGet(d, 'Tên-pháp-lệnh', 'Pháp lệnh vô danh');

                const safeId = name.replace(/\W/g, ''); 
                const isAbolished = window.stDecreeBuffer.abolished.includes(name);
                const opacity = isAbolished ? '0.5' : '1';

                let statusColor = '#8B6914'; 
                const lowerStatus = String(window.safeGet(d, 'Trạng-thái', '')).toLowerCase();
                if (lowerStatus.includes('hiệu lực')) statusColor = '#2D5016'; 
                if (lowerStatus.includes('bãi bỏ')) statusColor = '#8B2323'; 

                let cardHTML = `<div class="decree-card" style="opacity: ${opacity}">
                    <div class="decree-title">
                        <span>⚖️ ${name} ${isAbolished ? ' (Sắp bị bãi bỏ)' : ''}</span>
                        <span style="font-size: 0.75em; padding: 4px 10px; border-radius: 12px; background: ${statusColor}; color: #fff;">${window.safeGet(d, 'Trạng-thái', '???')}</span>
                    </div>
                    <div class="decree-meta"><span>🏷️ ${window.safeGet(d, 'Loại', 'Khác')}</span> | <span>📅 ${window.safeGet(d, 'Ngày-ban-hành', 'Chưa rõ')}</span></div>
                    <div class="decree-content"><b>Nội dung:</b><br> ${window.safeGet(d, 'Nội-dung', '...')}</div>
                    <div class="decree-effect"><b>Hệ lụy:</b><br> ${window.safeGet(d, 'Hiệu-quả-áp-dụng', 'Chưa có đánh giá.')}</div>`;

                if (!isAbolished) {
                    cardHTML += `<div style="margin-top: 15px; display: flex; justify-content: flex-end; gap: 8px; border-top: 1px dashed rgba(139,105,20,0.3); padding-top: 10px;">
                        <button class="action-btn" style="background: rgba(45, 80, 22, 0.1); color: #2D5016; border: 1px solid #2D5016; width: auto; padding: 6px 15px;" onclick="$('#edit-form-${safeId}').toggle()">📝 Sửa đổi</button>
                        <button class="action-btn" style="background: rgba(139, 35, 35, 0.1); color: #8B2323; border: 1px solid #8B2323; width: auto; padding: 6px 15px;" onclick="window.stBufferAbolishDecree('${name}')">🗑️ Bãi bỏ</button>
                    </div>
                    <div class="decree-edit-form" id="edit-form-${safeId}">
                        <div style="font-weight:bold; color:#4A3728; margin-bottom:5px;">Nội dung sửa đổi:</div>
                        <textarea class="new-decree-textarea" id="edit-content-${safeId}">${window.safeGet(d, 'Nội-dung', '')}</textarea>
                        <div style="margin-top:8px;">Trạng thái: <select class="new-decree-select" id="edit-status-${safeId}">
                            <option value="Đang hiệu lực" ${lowerStatus.includes('hiệu') ? 'selected' : ''}>Đang hiệu lực</option>
                            <option value="Tạm hoãn thi hành" ${lowerStatus.includes('hoãn') ? 'selected' : ''}>Tạm hoãn thi hành</option>
                        </select></div>
                        <div style="margin-top: 10px; text-align: right;"><button class="action-btn" style="background: #2D5016; color: white;" onclick="window.stBufferEditDecree('${name}', '${safeId}')">Lưu vào bộ đệm</button></div>
                    </div>`;
                }
                cardHTML += '</div>';
                dContainer.append(cardHTML);
            });
        }
        window.stRenderPendingList(); 
    };

    // --- Đưa lệnh ban hành mới vào Buffer ---
    window.stBufferNewDecree = function() {
        const type = $('#new-decree-type').val();
        const name = $('#new-decree-name').val().trim();
        const content = $('#new-decree-content').val().trim();
        if (!type || !name || !content) return alert("Xin Lãnh chúa điền đủ Loại, Tên và Nội dung!");

        window.stDecreeBuffer.new.push({ type: type, name: name, content: content });
        $('#new-decree-type').val(''); $('#new-decree-name').val(''); $('#new-decree-content').val('');
        window.stRenderPendingList();
    };

    // --- Đưa lệnh sửa đổi vào Buffer ---
    window.stBufferEditDecree = function(name, safeId) {
        const newContent = $('#edit-content-' + safeId).val().trim();
        const newStatus = $('#edit-status-' + safeId).val();
        let existingIdx = window.stDecreeBuffer.modified.findIndex(d => d.name === name);

        if (existingIdx >= 0) window.stDecreeBuffer.modified[existingIdx] = { name: name, content: newContent, status: newStatus };
        else window.stDecreeBuffer.modified.push({ name: name, content: newContent, status: newStatus });

        $('#edit-form-' + safeId).hide();
        window.stRenderPendingList();
    };

    // --- Đưa lệnh bãi bỏ vào Buffer ---
    window.stBufferAbolishDecree = function(name) {
        if(!window.stDecreeBuffer.abolished.includes(name)) {
            window.stDecreeBuffer.abolished.push(name);
            window.stRenderPendingList();
            window.renderDecreeModule(window.safeGet(window.getMVUVars(), 'stat-data.Pháp-lệnh', {})); 
        }
    };

    // --- Xóa lệnh khỏi Buffer nếu Lãnh chúa đổi ý ---
    window.stRemoveFromBuffer = function(category, index) {
        window.stDecreeBuffer[category].splice(index, 1);
        window.stRenderPendingList();
        if(category === 'abolished') window.renderDecreeModule(window.safeGet(window.getMVUVars(), 'stat-data.Pháp-lệnh', {})); 
    };

    // --- Render danh sách chờ duyệt ra màn hình ---
    window.stRenderPendingList = function() {
        const b = window.stDecreeBuffer;
        const total = b.new.length + b.modified.length + b.abolished.length;
        const pSec = $('#pending-section'); 
        const pList = $('#pending-list');

        if (total === 0) { pSec.hide(); return; }

        pSec.show(); pList.empty();
        b.new.forEach((d, i) => pList.append(`<div class="pending-item"><span class="pending-tag-new">MỚI</span> <b>${d.name}</b> <button onclick="window.stRemoveFromBuffer('new', ${i})">❌</button></div>`));
        b.modified.forEach((d, i) => pList.append(`<div class="pending-item"><span class="pending-tag-mod">SỬA</span> <b>${d.name}</b> <button onclick="window.stRemoveFromBuffer('modified', ${i})">❌</button></div>`));
        b.abolished.forEach((name, i) => pList.append(`<div class="pending-item"><span class="pending-tag-del">BÃI BỎ</span> <b>${name}</b> <button onclick="window.stRemoveFromBuffer('abolished', ${i})">❌</button></div>`));
    };

    // --- Công bố lệnh cho AI xử lý ---
    window.stPublishDecreesToAI = function() {
        const instruction = $('#publish-instruction').val().trim();
        const b = window.stDecreeBuffer;
        let promptMsg = "Ta muốn chính thức CÔNG BỐ các lệnh sau đây trên toàn lãnh thổ. AI hãy ghi nhận vào hệ thống và miêu tả phản ứng của các thế lực, dân chúng dựa trên hệ lụy của nó.\n";

        if (instruction) promptMsg += `\n🗣️ Lệnh truyền bá: "${instruction}"\n`;
        promptMsg += "\n--- CHI TIẾT ĐẠO LUẬT ---\n";

        b.new.forEach(d => promptMsg += `➕ [THÊM MỚI] Tên: ${d.name} | Loại: ${d.type} | Nội dung: ${d.content}\n`);
        b.modified.forEach(d => promptMsg += `📝 [SỬA ĐỔI] Pháp lệnh [${d.name}] -> Nội dung mới: ${d.content} | Trạng thái mới: ${d.status}\n`);
        b.abolished.forEach(name => promptMsg += `🗑️ [BÃI BỎ] Xóa bỏ hoàn toàn pháp lệnh: [${name}]. Cập nhật trạng thái thành 'Đã bãi bỏ'.\n`);

        promptMsg += `\n❗ BẮT BUỘC: Quan Chấp Hành phải tự động cập nhật lại biến MVU [${window.k('Pháp-lệnh')}] chính xác theo các thông tin ta vừa giao.`;

        window.sendCommandToAI(promptMsg);
        window.stDecreeBuffer = { new: [], modified: [], abolished: [] };
        $('#publish-instruction').val('');
        window.stRenderPendingList();
        $('#pane-decree').fadeOut(200).fadeIn(200); 
    };

   /* ==========================================================================
       PHẦN CUỐI: INITIALIZATION (Khởi chạy Toàn cục MVU & Quét Chat)
       ========================================================================== */
    async function init() {
        // Đợi hệ thống MVU của SillyTavern nạp xong dữ liệu
        if (typeof waitGlobalInitialized === 'function') {
            await waitGlobalInitialized('Mvu');
        }

        // Hàm gọi chung để render toàn bộ các mảng
        function runAllModules() {
            const allVars = window.getMVUVars();
            if (typeof window.populateCharacterData === 'function') window.populateCharacterData();
            if (typeof window.renderDecreeModule === 'function') window.renderDecreeModule(window.safeGet(allVars, 'stat-data.Pháp-lệnh', {}));

            // 👇 CHÍNH LÀ DÒNG NÀY: Gọi hàm quét Chat NSFW chạy cùng lúc với hệ thống
            if (typeof window.scanChatForNSFWStats === 'function') window.scanChatForNSFWStats();
        }

        // Chạy lần đầu tiên khi giao diện mở lên
        runAllModules();

        // Đăng ký sự kiện: Cứ mỗi khi AI chat xong, hệ thống tự động render lại bảng và quét chat
        if (typeof Mvu !== 'undefined' && Mvu.events && typeof eventOn === 'function') {
            eventOn(Mvu.events[window.k('VARIABLE-UPDATE-ENDED')], () => { runAllModules(); });
        }

        // Khởi tạo hiệu ứng gợn sóng (Ripple)
        $('summary').on('click', function(e) { window.addRippleEffect(e); });
    }

    // Bắt lỗi an toàn của môi trường SillyTavern
    if (typeof errorCatched === 'function') {
        $(errorCatched(init));
    } else {
        $(init);
    }

</script>
